def _daily_digest_progress_heartbeat(label: str, logger=print, interval: int = 20):
    stop_event = threading.Event()

    def _worker():
        elapsed = 0
        while not stop_event.wait(interval):
            elapsed += interval
            try:
                if logger:
                    logger(f"⏳ {label}仍在进行中，已等待约 {elapsed} 秒，请保持窗口开启。")
            except Exception:
                pass

    thread = threading.Thread(target=_worker, daemon=True)
    thread.start()
    return stop_event


def _daily_digest_today_cn() -> str:
    return datetime.now().strftime("%Y年%m月%d日")


def _daily_digest_iso_date() -> str:
    return datetime.now().strftime("%Y-%m-%d")


def _daily_digest_safe_text(value: str, max_chars: int = 800) -> str:
    text = re.sub(r"\s+", " ", str(value or "")).strip()
    return text[:max_chars].rstrip()


def _daily_digest_display_text(value: str, max_chars: int = 800) -> str:
    text = _daily_digest_safe_text(value, max_chars)
    if not text:
        return ""
    text = text.replace("。", "").replace("．", "")
    text = re.sub(r"\bet al\.", "et al", text, flags=re.I)
    text = re.sub(r"(?<=[\u4e00-\u9fffA-Za-z])\.(?=\s|$)", "", text)
    return text.strip()


def _daily_digest_display_meta(value: str, max_chars: int = 800) -> str:
    text = _daily_digest_safe_text(value, max_chars)
    text = text.replace("。", "").replace("．", "")
    return re.sub(r"\bet al\.", "et al", text, flags=re.I).strip()


def _daily_digest_clean_affiliation(value: str, max_chars: int = 180) -> str:
    text = _daily_digest_safe_text(value, 500)
    if not text:
        return ""
    text = re.sub(r"[\w.+-]+@[\w.-]+\.[A-Za-z]{2,}", "", text)
    text = re.sub(r"(?:电子邮箱|电子邮件|邮箱|E-?mail|Electronic address)\s*[:：]?\s*", "", text, flags=re.I)
    text = re.sub(r"(?:美国|中国|英国|加拿大|日本|德国|法国|澳大利亚|瑞士|意大利|荷兰|西班牙|新加坡|韩国)\s*[:：]?\s*$", "", text)
    text = re.sub(r"\b(?:USA|United States|United States of America|U\.S\.A\.?|US|UK|China|PR China|P\.R\. China)\b\.?", "", text, flags=re.I)
    text = re.sub(r"\b[A-Z]{2}\s*\d{5}(?:-\d{4})?\b", "", text)
    text = re.sub(r"\b\d{5,6}\b", "", text)
    text = re.sub(r"\s+", " ", text).strip(" ,，;；.。")
    if not text:
        return ""

    cleaned_parts: list[str] = []
    for block in [x.strip() for x in re.split(r"[;；]+", text) if x.strip()]:
        segments = [s.strip(" ,，.。") for s in re.split(r"[,，]+", block) if s.strip(" ,，.。")]
        keep: list[str] = []
        for segment in segments:
            if not segment:
                continue
            if re.fullmatch(r"(?:CA|NY|MA|PA|TX|WA|IL|MD|NC|NJ|OH|MI|FL|GA|VA|DC|Stanford|Boston|New York|Cambridge|London|Paris|Tokyo|Shanghai|Beijing)", segment, flags=re.I):
                continue
            if re.fullmatch(r"(?:斯坦福|加州|纽约|波士顿|剑桥|伦敦|巴黎|东京|上海|北京|美国|中国|英国|加拿大|日本|德国|法国|澳大利亚|瑞士|意大利|荷兰|西班牙|新加坡|韩国)", segment):
                continue
            if re.search(r"\b(?:street|road|avenue|drive|boulevard|building|floor|room|campus|city|province|postal|zip)\b", segment, flags=re.I):
                continue
            if re.search(r"(?:省|市|区|邮编|地址|街|路|号)$", segment):
                continue
            keep.append(segment)
            if len(keep) >= 2:
                break
        part = "，".join(keep).strip(" ,，;；.。")
        if part and part not in cleaned_parts:
            cleaned_parts.append(part)
        if len(cleaned_parts) >= 2:
            break
    return _daily_digest_safe_text("；".join(cleaned_parts), max_chars)


def _daily_digest_parse_journals(raw: str = "") -> list[str]:
    if not str(raw or "").strip():
        return list(DAILY_RESEARCH_DEFAULT_JOURNALS)
    items = [x.strip() for x in re.split(r"[,;，；\n]+", str(raw or "")) if x.strip()]
    return items or list(DAILY_RESEARCH_DEFAULT_JOURNALS)


def _daily_digest_journal_key(value: str) -> str:
    return re.sub(r"\s+", " ", str(value or "").strip()).lower()


def _daily_digest_match_journal_key(journal: str, journal_keys: list[str]) -> str:
    full = _daily_digest_journal_key(journal)
    if not full:
        return ""
    if full in journal_keys:
        return full
    aliases = {
        "pnas": ("proceedings of the national academy of sciences", "proc natl acad sci"),
        "journal of neuroscience": ("journal of neuroscience", "j neurosci"),
        "nature neuroscience": ("nature neuroscience",),
        "nature medicine": ("nature medicine",),
        "nature methods": ("nature methods",),
        "elife": ("elife", "e-life"),
    }
    for key in journal_keys:
        for alias in aliases.get(key, ()):
            if alias in full:
                return key
        if len(key) >= 8 and (full.startswith(key + " ") or full.startswith(key + ":") or full.startswith(key + " :")):
            return key
    return ""


