def _daily_digest_local_digest(articles: list[dict], date_text: str) -> dict:
    cooked = []
    for item in articles:
        title = item.get("title", "")
        abstract = item.get("abstract", "")
        finding = _daily_digest_safe_text(abstract, 120)
        cooked.append({
            "pmid": item.get("pmid", ""),
            "title_cn": title,
            "authors_cn": item.get("authors", "") or "作者信息待补全",
            "affiliation_cn": _daily_digest_clean_affiliation(item.get("affiliations", "")) or "机构信息待补全",
            "research_question": "一条特定神经通路，为什么会改变我们对身体信号的感受？",
            "evidence_path": "论文摘要提供了研究对象、关键方法和主要变量。",
            "key_finding": finding,
            "conclusion_cn": "这些结果支持论文关于相关神经机制的判断。",
            "why_it_matters": "这有助于梳理论文涉及的神经机制和实验边界。",
            "scope_note": "该结论应限于摘要所描述的实验条件，不能直接等同于临床疗效。",
            "voiceover": f"一条特定神经通路，为什么会改变我们对身体信号的感受？论文摘要显示，研究围绕相关神经机制展开。核心结果是：{finding}。这些结果支持论文关于该机制的判断。需要注意的是，结论应限于摘要所描述的实验条件。这篇论文题为《{title}》，由{item.get('authors','作者信息待补全')}等人完成。",
            "image_prompt": _daily_digest_image_prompt(item, finding),
        })
    return {
        "date": date_text,
        "short_title": "脑科学追新",
        "video_title": f"【全澜脑科学®追新助手】{datetime.now().strftime('%Y%m%d')}01期",
        "video_description": "",
        "opening_voiceover": f"{cooked[0]['research_question']} 今天是{date_text}，这里是全澜脑科学每日研究速递。" if cooked else f"今天有哪些神经科学问题值得追踪？今天是{date_text}，这里是全澜脑科学每日研究速递。",
        "catalog_voiceover": f"今天选取 {len(cooked)} 篇神经科学论文，分别看它们的方法、结果和证据边界。",
        "articles": cooked,
        "closing_voiceover": "关注全澜脑科学，下一期继续追踪具体问题和证据边界。",
    }


def _daily_digest_extract_json(text: str) -> dict:
    raw = str(text or "").strip()
    if not raw:
        return {}
    raw = re.sub(r"^```(?:json)?\s*", "", raw, flags=re.I).strip()
    raw = re.sub(r"\s*```$", "", raw).strip()
    m = re.search(r"\{.*\}", raw, flags=re.S)
    if m:
        raw = m.group(0)
    try:
        return json.loads(raw)
    except Exception:
        return {}


def _daily_digest_polish_prompt(digest: dict, date_text: str) -> str:
    payload = {
        "date": digest.get("date", date_text),
        "short_title": digest.get("short_title", ""),
        "video_title": digest.get("video_title", ""),
        "video_description": digest.get("video_description", ""),
        "opening_voiceover": digest.get("opening_voiceover", ""),
        "catalog_voiceover": digest.get("catalog_voiceover", ""),
        "articles": [],
        "closing_voiceover": digest.get("closing_voiceover", ""),
    }
    for item in digest.get("articles", []) or []:
        payload["articles"].append({
            "pmid": item.get("pmid", ""),
            "title_cn": item.get("title_cn", ""),
            "authors_cn": item.get("authors_cn", ""),
            "affiliation_cn": _daily_digest_clean_affiliation(item.get("affiliation_cn", "")),
            "research_question": item.get("research_question") or item.get("hook", ""),
            "evidence_path": item.get("evidence_path", ""),
            "key_finding": item.get("key_finding", ""),
            "conclusion_cn": item.get("conclusion_cn", ""),
            "why_it_matters": item.get("why_it_matters", ""),
            "scope_note": item.get("scope_note", ""),
            "voiceover": item.get("voiceover", ""),
        })
    source = json.dumps(payload, ensure_ascii=False, indent=2)
    return f"""你是全澜脑科学“每日研究速递”的 DeepSeek 终稿作者。请同时扮演三种角色：
1. 顶尖神经科学家：像 CNS 审稿人一样检查术语、机制、证据强度和外推边界。
2. 中文语言学家：检查主谓宾、修饰关系、搭配、指代、成分完整和中文节奏。
3. 科研结果快报编辑：把论文结果写成准确、易懂、有信息密度的短视频口播稿。
4. 微信短视频主编：确保第一句先给具体科学问题，不用“欢迎来到/今天分享/本期关注”拖慢进入。

下面 JSON 已由 GPT 完成文献翻译和结构化初稿。你的任务不是重写论文，也不是发挥想象，而是在原字段已有信息范围内，把它改成“专业人士能快速听懂的科研结果快报”。

目标读者：有生物学、医学、心理学、神经科学或理工科背景的人，也包括微信视频号里关心脑科学前沿、但没有时间读完整论文的普通知识受众。他们在午饭、通勤或碎片时间阅读。内容要准确、清楚、克制，但不能像论文摘要，也不能像宣传稿。

总原则：
1. 忠于原文信息，不新增摘要外事实；不得把相关性写成因果，不得把动物或体外结果写成人类临床结论。
2. 先保证科学准确，再保证中文顺口。每一句都要能回答“谁/什么，用什么方法，发现了什么，说明到什么程度”。
3. 写作目标是“科研结果快报”：不铺垫、不煽情、不卖关子；用短句把科学问题、方法、结果、结论、意义和边界讲清楚。
4. 每个字段都要优先保留具体对象：脑区、细胞、环路、受体、行为、模型、疾病机制、记录信号、样本或实验系统。不要把信息磨成“相关机制值得进一步研究”这类正确废话。

语言硬规则：
1. 修复所有语病、生硬翻译腔、搭配不当、指代不清、缺成分、重复和 AI 味。
2. 每句话只表达一个核心意思。尽量 18-32 个汉字；超过 40 个汉字必须拆句。
3. 避免多层定语、连续从句、连续三个以上逗号。不要用英文论文句法硬翻中文。
4. 严禁字段以“研究聚焦”“研究结合”“研究发现”“这说明”“目前仍需注意”这类机械模板开头。
5. 不要写“证据链”“证据路径”“构成的证据”“提供新的研究角度”“提供新思路”“重要线索”“重大意义”“为后续研究提供依据”等空泛套话。
6. 不要写“突破”“颠覆”“重塑”“改变局面”等拔高词。需要表达价值时，具体说它帮助理解什么机制、改进什么模型、支持什么测量或提示什么边界。不要把“提供依据/提供线索/用于后续研究”写进科学问题。
7. 不要把生物过程拟人化。严禁“内吞作用主动提供……”这类句子。
8. 不要写缺少限定对象的短语。比如“建立和维持连接”必须改为“建立和维持神经元之间的连接”或“建立和维持突触连接”。
9. 所有机构只写单位名。不得包含城市、州名、邮编、国家、详细地址、电子邮箱或 Electronic address。
10. opening_voiceover 不得以“欢迎大家来到”“今天是”“本期关注”“接下来我们”开头；它应先抛出本期最有抓力的一条具体科学问题，再用半句交代日期/期号。

神经科学硬规则：
1. 必须校正专业术语和大小写，例如 AgRP 不得写成 AqRP；Sim2、PVH/PVN、下丘脑室旁核等术语要前后一致。
2. 小众术语第一次出现时顺手解释。解释要短，嵌入句子，不写词典定义。
3. 机制词必须有明确对象。比如“连接”要说清是神经元之间的连接、突触连接、功能连接还是白质连接。
4. 如果是细胞、环路、类器官、小鼠、猕猴、体外模型或 1 期临床试验，必须保留对应证据边界。
5. 如果原文只支持“相关、参与、提示”，不要改成“导致、决定、证明、解释了全部机制”。

字段要求：
1. title_cn：忠于英文题名，写成正式、通顺的中文学术标题。
2. research_question：一句钩子式科学问题，只能有一个问号。它要先让人理解问题，再落到论文机制。不要写“该研究旨在”“这项研究想回答的是”。不要双问。严禁把研究意义写成问题，例如“如何为后续研究提供依据”“如何提供线索”“为什么具有意义”。
3. evidence_path：一句说明研究对象和关键方法。自然表达，不要写“方法上”。
4. key_finding：一句说明最核心结果。必须有主语和宾语，不能只堆术语。
5. conclusion_cn：一句说明这些结果支持什么判断。语气克制。
6. why_it_matters：一句说明科学意义。不得泛泛写“提供新思路”“提供依据”“提供线索”。必须有明确对象，例如某个环路、细胞类型、模型、测量方法或病理机制。
7. scope_note：一句说明边界。明确模型、样本、实验系统或临床阶段。
8. voiceover：5-7 个短句，可直接口播。顺序是：科学问题；方法；结果；结论；意义/边界；最后交代期刊、题名、作者和简要单位。第一句必须是 research_question 的自然版本。
9. opening_voiceover 和 catalog_voiceover：只事实性介绍本期论文数量和主题，不编造牵强共同主题。opening_voiceover 第一整句必须是具体科学问题，不能是栏目问候语。
10. short_title：16 个汉字以内，适合封面主题。
11. video_title：格式必须是“【全澜®追新助手】YYYYMMDDNN期 XXXXX”。
12. video_description：约 150 字，直接介绍今天有哪些研究；准确、有信息密度、无营销腔。

输出前逐条自检：
1. 有没有英文直译腔？
2. 有没有缺主语、缺宾语、指代不明？
3. 有没有“连接”“调控”“作用”“机制”这类词没有对象？
4. 有没有把相关性写成因果？
5. 有没有把证据边界说丢？
6. 有没有口水话或空泛价值判断？
7. opening_voiceover 第一整句是不是具体科学问题？

保持 JSON 结构、字段名、文章数量和 pmid 不变；不要 Markdown，不要解释。

只输出润色后的严格 JSON：
{source}
"""

def _daily_digest_polish_with_deepseek(data: dict, *, date_text: str, deepseek_key: str = "", logger=print) -> dict:
    if not data or not isinstance(data.get("articles"), list):
        return data
    prompt = _daily_digest_polish_prompt(data, date_text)
    if logger:
        logger(f"🪄 DeepSeek 润色开始：{len(data.get('articles', []) or [])} 篇，正在优化中文短句、术语解释和表达边界...")
    heartbeat = _daily_digest_progress_heartbeat("DeepSeek 中文润色", logger, interval=15)
    try:
        result = generate_text_by_engine(
            "DeepSeek Chat（官方润色）",
            prompt,
            logger,
            deepseek_key=deepseek_key or load_deepseek_api_key(),
        )
    finally:
        heartbeat.set()
    if logger:
        logger(f"✅ DeepSeek 润色返回：{len(str(result or ''))} 字符，正在解析 JSON...")
    polished = _daily_digest_extract_json(result)
    if not polished or not isinstance(polished.get("articles"), list):
        if logger:
            logger("⚠️ DeepSeek 润色未返回可解析 JSON，保留 GPT 初稿。")
        return data
    allowed_article_fields = (
        "title_cn",
        "authors_cn",
        "affiliation_cn",
        "research_question",
        "evidence_path",
        "key_finding",
        "conclusion_cn",
        "why_it_matters",
        "scope_note",
        "voiceover",
    )
    data["opening_voiceover"] = polished.get("opening_voiceover") or data.get("opening_voiceover", "")
    data["catalog_voiceover"] = polished.get("catalog_voiceover") or data.get("catalog_voiceover", "")
    data["closing_voiceover"] = polished.get("closing_voiceover") or data.get("closing_voiceover", "")
    data["short_title"] = polished.get("short_title") or data.get("short_title", "")
    data["video_title"] = polished.get("video_title") or data.get("video_title", "")
    data["video_description"] = polished.get("video_description") or data.get("video_description", "")
    polished_items = polished.get("articles", []) or []
    for idx, item in enumerate(data.get("articles", []) or []):
        candidate = polished_items[idx] if idx < len(polished_items) else {}
        if str(candidate.get("pmid", "")).strip() and str(item.get("pmid", "")).strip():
            if str(candidate.get("pmid", "")).strip() != str(item.get("pmid", "")).strip():
                continue
        for field in allowed_article_fields:
            value = str(candidate.get(field, "") or "").strip()
            if value:
                item[field] = value
    if logger:
        logger("✅ DeepSeek 润色解析完成，已写回栏目素材。")
    return data


def build_daily_research_digest(
    articles: list[dict],
    *,
    date_text: str,
    text_engine: str = "GPT-5.5",
    polish_engine: str = "DeepSeek Chat（官方润色）",
    deepseek_key: str = "",
    openai_key: str = "",
    image_key: str = "",
    chatshare_key: str = "",
    gemini_key: str = "",
    grok_key: str = "",
    logger=print,
) -> dict:
    prompt = _daily_digest_llm_prompt(articles, date_text)
    if not (is_openai_text_engine(text_engine) or is_gemini_text_engine(text_engine)):
        text_engine = "GPT-5.5"
    if logger:
        logger(f"🧠 结构化初稿开始：{text_engine}，{len(articles or [])} 篇；该步骤通常需要几十秒。")
    heartbeat = _daily_digest_progress_heartbeat("文献翻译与结构化初稿", logger, interval=15)
    try:
        result = generate_text_by_engine(
            text_engine,
            prompt,
            logger,
            deepseek_key=deepseek_key or load_deepseek_api_key(),
            openai_key=openai_key or load_openai_api_key(),
            chatshare_key="",
            gemini_key=gemini_key or load_gemini_api_key(),
            grok_key=grok_key or load_grok_api_key(),
        )
    finally:
        heartbeat.set()
    if logger:
        if result:
            logger(f"✅ 结构化初稿返回：{len(str(result or ''))} 字符，正在解析 JSON...")
        else:
            logger("⚠️ 结构化初稿未返回有效内容，准备使用本地保守模板。")
    data = _daily_digest_extract_json(result)
    if not data or not isinstance(data.get("articles"), list):
        if logger:
            logger("⚠️ 文本模型未返回可解析 JSON，已使用本地保守模板生成素材。")
        data = _daily_digest_local_digest(articles, date_text)
    if is_deepseek_text_engine(polish_engine):
        data = _daily_digest_polish_with_deepseek(data, date_text=date_text, deepseek_key=deepseek_key, logger=logger)
    by_pmid = {str(x.get("pmid", "")): x for x in articles}
    for idx, item in enumerate(data.get("articles", [])):
        pmid = str(item.get("pmid", "")).strip()
        source = by_pmid.get(pmid) or (articles[idx] if idx < len(articles) else {})
        item["source"] = source
        if not item.get("authors_cn"):
            item["authors_cn"] = source.get("authors", "") or "作者信息待补全"
        item["affiliation_cn"] = _daily_digest_clean_affiliation(item.get("affiliation_cn") or source.get("affiliations", "")) or "机构信息待补全"
        if not item.get("research_question") and item.get("hook"):
            item["research_question"] = item.get("hook")
        if not item.get("evidence_path"):
            item["evidence_path"] = _daily_digest_infer_evidence_path(source)
        if not item.get("conclusion_cn"):
            finding_for_conclusion = _daily_digest_strip_tail_punctuation(item.get("key_finding") or source.get("title", ""))
            if finding_for_conclusion:
                item["conclusion_cn"] = f"这些结果支持论文关于{finding_for_conclusion}的核心判断"
        if not item.get("scope_note"):
            item["scope_note"] = _daily_digest_infer_scope_note(source)
        item = _daily_digest_normalize_article_copy(item)
        item["voiceover"] = _daily_digest_voiceover_with_hook(item)
        warnings = _daily_digest_copy_quality_warnings(" ".join(str(item.get(k, "")) for k in ("research_question", "evidence_path", "key_finding", "conclusion_cn", "why_it_matters", "scope_note", "voiceover")))
        if warnings and logger:
            logger(f"⚠️ 文案质检提示：PMID {source.get('pmid', pmid) or pmid} 可能存在 {', '.join(sorted(set(warnings)))}。")
        item["image_prompt"] = _daily_digest_force_square_image_prompt(
            source,
            item.get("image_prompt") or _daily_digest_image_prompt(source, item.get("key_finding", "")),
            item.get("key_finding", ""),
        )
    data = _daily_digest_finalize_metadata(data)
    if logger:
        logger("✅ 栏目素材字段校验完成，已补齐 source、边界说明和图片提示词。")
    return data


DAILY_DIGEST_VISUAL_W = 760
DAILY_DIGEST_VISUAL_H = 760
DAILY_DIGEST_VISUAL_API_SIZE = "1024x1024"


def _daily_digest_normalize_visual_summary(path: str, logger=None) -> bool:
    """Normalize visual_summaries to the exact article-card image slot size."""
    try:
        from PIL import Image
        if not path or not os.path.exists(path):
            return False
        with Image.open(path) as opened:
            visual = opened.convert("RGB")
        if visual.size == (DAILY_DIGEST_VISUAL_W, DAILY_DIGEST_VISUAL_H):
            return True
        visual = _daily_digest_square_visual_no_crop(visual)
        visual.save(path, "PNG")
        if logger:
            logger(f"🖼️ 图片摘要已无裁切归一化：{DAILY_DIGEST_VISUAL_W}×{DAILY_DIGEST_VISUAL_H} | {os.path.basename(path)}")
        return True
    except Exception as e:
        if logger:
            logger(f"⚠️ 图片摘要规格统一失败：{str(e)[:120]}")
        return False


def _daily_digest_prepare_existing_visual_summary(path: str, logger=None) -> bool:
    """Resume helper: trust real image files on disk, including raw backups."""
    try:
        from PIL import Image
        if not path:
            return False
        candidates = [path, os.path.join(os.path.dirname(path), "_raw", os.path.basename(path))]
        for candidate in candidates:
            if not candidate or not os.path.exists(candidate):
                continue
            try:
                with Image.open(candidate) as opened:
                    visual = opened.convert("RGB")
            except Exception:
                continue
            os.makedirs(os.path.dirname(path), exist_ok=True)
            if os.path.abspath(candidate) != os.path.abspath(path):
                visual = _daily_digest_square_visual_no_crop(visual)
                visual.save(path, "PNG")
                if logger:
                    logger(f"♻️ 续作识别到 raw 图片摘要，已恢复到正式位置：{os.path.basename(path)}")
                return True
            return _daily_digest_normalize_visual_summary(path, logger=logger)
    except Exception as exc:
        if logger:
            logger(f"⚠️ 续作检查已有图片摘要失败：{str(exc)[:120]}")
    return False


def _daily_digest_square_visual_no_crop(visual):
    from PIL import Image
    visual = visual.convert("RGB")
    target = (DAILY_DIGEST_VISUAL_W, DAILY_DIGEST_VISUAL_H)
    if visual.size == target:
        return visual
    resample = getattr(getattr(Image, "Resampling", Image), "LANCZOS", Image.LANCZOS)
    scale = min(DAILY_DIGEST_VISUAL_W / max(1, visual.width), DAILY_DIGEST_VISUAL_H / max(1, visual.height))
    new_w = max(1, int(round(visual.width * scale)))
    new_h = max(1, int(round(visual.height * scale)))
    fitted = visual.resize((new_w, new_h), resample)
    canvas = Image.new("RGB", target, "#F7F4EF")
    canvas.paste(fitted, ((DAILY_DIGEST_VISUAL_W - new_w) // 2, (DAILY_DIGEST_VISUAL_H - new_h) // 2))
    return canvas


def _daily_digest_image_prompt(article: dict, key_finding: str = "") -> str:
    title = _daily_digest_safe_text(article.get("title", ""), 240)
    abstract = _daily_digest_safe_text(article.get("abstract", ""), 900)
    key = _daily_digest_safe_text(key_finding, 220)
    return f"""DAILY_RESEARCH_SQUARE_VISUAL_SUMMARY.
Cell-style neuroscience visual abstract, clean biomedical editorial illustration, no text, no labels, no letters, no numbers, no watermark.
Represent the main finding of this paper as a clear visual mechanism: {title}.
Key finding to express visually: {key}.
Use accurate neuroscience imagery only when supported by the abstract: {abstract}
Composition: redraw the mechanism as a purpose-built square figure. Do not draw a full-height animal body or a long head-to-tail vertical pathway. If animal context is needed, use simplified partial mouse/head/body icons arranged inside the square. Compress the pathway into a balanced square mechanism map: central circuit, compact arrows, one optional inset, or 2-3 stages arranged radially or in a grid. All essential objects must be fully visible inside the square.
Canvas requirement: square visual abstract, request image canvas exactly {DAILY_DIGEST_VISUAL_API_SIZE}, aspect ratio 1:1. The final normalized local visual_summaries image will be exactly {DAILY_DIGEST_VISUAL_W}x{DAILY_DIGEST_VISUAL_H} pixels. Fill the whole square frame with the mechanism; keep important content away from the outer 8 percent edge.
Avoid: written words, UI elements, fake microscopy labels, gore, sensational imagery, unsupported disease claims."""


def _daily_digest_force_square_image_prompt(article: dict, prompt: str, key_finding: str = "") -> str:
    title = _daily_digest_safe_text((article or {}).get("title", ""), 240)
    abstract = _daily_digest_safe_text((article or {}).get("abstract", ""), 700)
    key = _daily_digest_safe_text(key_finding, 220)
    body = _daily_digest_safe_text(prompt, 1400)
    if "DAILY_RESEARCH_SQUARE_VISUAL_SUMMARY" in body:
        body = re.sub(r"\s+", " ", body).strip()
    return f"""DAILY_RESEARCH_SQUARE_VISUAL_SUMMARY.
Create a purpose-built 1:1 square Cell-style neuroscience visual abstract, not a cropped vertical poster.
Source title: {title}
Key finding: {key}
Source-supported context: {abstract}
Original visual idea to preserve if useful: {body}
Hard composition rule: all scientific content must be drawn directly inside one square canvas. Do not draw a full-height animal body, long head-to-tail vertical pathway, tall mobile page, infographic poster, or screenshot-like page. Recompose the mechanism into a compact square map with central circuit, short arrows, one optional inset, or 2-3 balanced stages. If mouse or organs are needed, use simplified partial icons or compact cutaways inside the square; never rely on cropping to fit them.
Canvas requirement: request image canvas exactly {DAILY_DIGEST_VISUAL_API_SIZE}, aspect ratio 1:1. Keep all essential structures, arrows, insets, and mechanism stages fully visible inside the square with generous margins.
Style: clean biomedical editorial illustration, Cell visual abstract feeling, mechanism-first, no text, no labels, no letters, no numbers, no watermark."""


def _daily_digest_font(size: int, *, weight: int = 500):
    finder = globals().get("_find_postprocess_font")
    if callable(finder):
        try:
            return finder(size, prefer_cjk=True, weight=weight)
        except Exception:
            pass
    try:
        from PIL import ImageFont
        return ImageFont.truetype("msyh.ttc", size)
    except Exception:
        from PIL import ImageFont
        return ImageFont.load_default()


def _daily_digest_wrap(draw, text: str, font, max_width: int, max_lines: int = 8) -> list[str]:
    text = _daily_digest_safe_text(text, 1200)
    if not text:
        return []
    lines, current = [], ""
    tokens = list(text) if re.search(r"[\u4e00-\u9fff]", text) else re.split(r"(\s+)", text)
    for token in tokens:
        probe = current + token
        try:
            width = draw.textbbox((0, 0), probe, font=font)[2]
        except Exception:
            width = len(probe) * 12
        if current and width > max_width:
            if str(token).strip() in "，。！？；：、,.!?;:)）】》」』":
                current = probe
                continue
            lines.append(current.strip())
            current = token.strip()
            if len(lines) >= max_lines:
                break
        else:
            current = probe
    if current.strip() and len(lines) < max_lines:
        lines.append(current.strip())
    if len(lines) > max_lines:
        lines = lines[:max_lines]
    for i in range(1, len(lines)):
        if lines[i] and lines[i][0] in "，。！？；：、,.!?;:)）】》」』" and lines[i - 1]:
            lines[i - 1] += lines[i][0]
            lines[i] = lines[i][1:].lstrip()
    lines = [line for line in lines if line]
    lines = _daily_digest_fix_cjk_orphan_lines(lines)
    lines = _daily_digest_fix_cjk_protected_terms(lines, draw, font, max_width)
    lines = _daily_digest_fix_cjk_orphan_lines(lines)
    return lines


def _daily_digest_is_cjk_char(ch: str) -> bool:
    return bool(ch and re.match(r"[\u4e00-\u9fff]", ch))


def _daily_digest_fix_cjk_orphan_lines(lines: list[str]) -> list[str]:
    fixed = [str(line or "").strip() for line in lines if str(line or "").strip()]
    for _ in range(3):
        changed = False
        for i in range(1, len(fixed)):
            cur = fixed[i].strip()
            prev = fixed[i - 1].strip()
            if len(cur) == 1 and _daily_digest_is_cjk_char(cur) and len(prev) > 1 and _daily_digest_is_cjk_char(prev[-1]):
                fixed[i - 1] = prev[:-1].rstrip()
                fixed[i] = (prev[-1] + cur).strip()
                changed = True
        fixed = [line for line in fixed if line]
        if not changed:
            break
    return fixed


def _daily_digest_text_width(draw, text: str, font) -> int:
    try:
        bbox = draw.textbbox((0, 0), text, font=font)
        return bbox[2] - bbox[0]
    except Exception:
        return len(str(text or "")) * 12


def _daily_digest_fix_cjk_protected_terms(lines: list[str], draw, font, max_width: int) -> list[str]:
    fixed = [str(line or "").strip() for line in lines if str(line or "").strip()]
    protected_terms = (
        "丘脑皮层", "丘脑", "皮层", "环路", "睡眠", "感觉", "输入", "门控",
        "星形胶质细胞", "胶质细胞", "星形胶质", "突触", "巩固", "学习",
        "单细胞", "图谱", "帕金森病", "神经炎症", "炎症", "轨迹",
        "前额叶", "海马", "同步", "灵活决策", "决策",
        "皮层类器官", "类器官", "自闭症", "发育", "偏移",
    )
    for _ in range(2):
        changed = False
        for i in range(1, len(fixed)):
            prev = fixed[i - 1]
            cur = fixed[i]
            for term in protected_terms:
                if len(term) < 2:
                    continue
                for split_at in range(1, len(term)):
                    left, right = term[:split_at], term[split_at:]
                    if prev.endswith(left) and cur.startswith(right):
                        candidate_prev = prev[:-len(left)].rstrip()
                        candidate_cur = (left + cur).strip()
                        if candidate_prev and _daily_digest_text_width(draw, candidate_cur, font) <= max_width:
                            fixed[i - 1] = candidate_prev
                            fixed[i] = candidate_cur
                            changed = True
                            break
                if changed:
                    break
        fixed = [line for line in fixed if line]
        if not changed:
            break
    return fixed


def _daily_digest_lines_height(draw, lines: list[str], font, line_gap: int = 8) -> int:
    total = 0
    visible = [line for line in lines if line]
    for idx, line in enumerate(visible):
        try:
            bbox = draw.textbbox((0, 0), line, font=font)
            line_h = bbox[3] - bbox[1]
        except Exception:
            line_h = getattr(font, "size", 24)
        total += line_h
        if idx < len(visible) - 1:
            total += line_gap
    return total


def _daily_digest_clean_card_body_lines(lines: list[str]) -> list[str]:
    cleaned = []
    bad_tail = re.compile(r"[，,、；;：:\s]*(?:和|及|以及|并|与|或|对|在|将|把|为|以|通过|结合|采用)$")
    for line in [str(x or "").strip() for x in lines if str(x or "").strip()]:
        new_line = bad_tail.sub("", line).strip()
        if new_line != line and new_line and not re.search(r"[。！？!?…]$", new_line):
            new_line += "…"
        cleaned.append(new_line or line)
    return cleaned


def _daily_digest_draw_lines(draw, lines: list[str], xy, font, fill, max_width, line_gap=8, align: str = "left"):
    x, y = xy
    align = str(align or "left").lower()
    for line in [line for line in lines if line]:
        bbox = draw.textbbox((0, 0), line, font=font)
        line_w = bbox[2] - bbox[0]
        line_h = bbox[3] - bbox[1]
        line_x = x + max(0, (max_width - line_w) // 2) if align == "center" else x
        draw.text((line_x, y), line, font=font, fill=fill)
        y += line_h + line_gap
    return y


def _daily_digest_draw_wrapped(draw, text, xy, font, fill, max_width, line_gap=8, max_lines=8, align: str = "left"):
    lines = _daily_digest_wrap(draw, text, font, max_width, max_lines=max_lines)
    return _daily_digest_draw_lines(draw, lines, xy, font, fill, max_width, line_gap=line_gap, align=align)


def _daily_digest_fit_wrapped_text(draw, text: str, *, max_width: int, max_height: int, min_size: int, max_size: int, weight: int = 850, max_lines: int = 3):
    text = str(text or "").strip()
    for size in range(max_size, min_size - 1, -2):
        font = _daily_digest_font(size, weight=weight)
        line_gap = max(6, int(size * 0.18))
        lines = _daily_digest_wrap(draw, text, font, max_width, max_lines=max_lines)
        if not lines:
            continue
        if "".join(lines).replace("…", "") != text.replace(" ", "") and lines[-1].endswith("…"):
            continue
        height = _daily_digest_lines_height(draw, lines, font, line_gap=line_gap)
        if height <= max_height:
            return font, lines, line_gap, height
    font = _daily_digest_font(min_size, weight=weight)
    line_gap = max(6, int(min_size * 0.18))
    lines = _daily_digest_wrap(draw, text, font, max_width, max_lines=max_lines)
    height = _daily_digest_lines_height(draw, lines, font, line_gap=line_gap)
    return font, lines, line_gap, height


def _daily_digest_plan_article_body(draw, paragraphs: list[str], *, max_width: int, max_height: int):
    def _card_body_text(value: str, max_chars: int = 128) -> str:
        raw = _daily_digest_display_text(value, 420)
        if not raw:
            return ""
        truncated = len(raw) > max_chars
        text = raw[:max_chars].rstrip() if truncated else raw
        text = re.sub(r"[，,、；;：:\s]*(?:和|及|以及|并|与|或|对|在|将|把|为|以|通过|结合|采用)$", "", text).strip()
        text = re.sub(r"[，,、；;：:\s]+$", "", text).strip()
        if truncated and text and not text.endswith("…"):
            text += "…"
        return text

    clean = [_card_body_text(p, 128) for p in paragraphs if _card_body_text(p, 128)]
    if not clean:
        clean = ["围绕论文摘要提取研究问题、关键证据与适用边界，供口播解读时快速抓住主线。"]
    clean = clean[:3]
    for size in (30, 29, 28, 27, 26, 25, 24):
        font = _daily_digest_font(size, weight=500)
        line_gap = max(7, int(size * 0.28))
        para_gap = max(13, int(size * 0.52))
        for max_lines_each in (2, 1):
            planned = []
            total_h = 0
            for para in clean:
                lines = _daily_digest_wrap(draw, para, font, max_width, max_lines=max_lines_each)
                lines = _daily_digest_clean_card_body_lines(lines)
                if not lines:
                    continue
                planned.append(lines)
                total_h += _daily_digest_lines_height(draw, lines, font, line_gap=line_gap) + para_gap
            if planned:
                total_h -= para_gap
            if total_h <= max_height:
                return font, planned, line_gap, para_gap
    font = _daily_digest_font(24, weight=500)
    line_gap = 7
    para_gap = 13
    planned = []
    for para in clean[:3]:
        lines = _daily_digest_wrap(draw, para, font, max_width, max_lines=2)
        lines = _daily_digest_clean_card_body_lines(lines)
        if lines:
            planned.append(lines)
    while planned:
        total_h = sum(_daily_digest_lines_height(draw, lines, font, line_gap=line_gap) for lines in planned) + para_gap * (len(planned) - 1)
        if total_h <= max_height:
            break
        planned.pop()
    if planned and clean:
        last = planned[-1]
        if last and not last[-1].endswith("…") and len(clean) > len(planned):
            last[-1] = re.sub(r"[，。；、,\s]+$", "", last[-1]) + "…"
    return font, planned, line_gap, para_gap


def _daily_digest_planned_text_height(draw, planned: list[list[str]], font, line_gap: int, para_gap: int) -> int:
    if not planned:
        return 0
    return sum(_daily_digest_lines_height(draw, lines, font, line_gap=line_gap) for lines in planned) + para_gap * (len(planned) - 1)


def _daily_digest_card_base(w: int = 1080, h: int = 1920):
    from PIL import Image, ImageDraw
    img = Image.new("RGB", (w, h), "#F5F8FB")
    d = ImageDraw.Draw(img)
    d.rectangle((0, 0, w, int(h * 0.13)), fill="#E7F0F7")
    d.rectangle((0, int(h * 0.86), w, h), fill="#EAF2F7")
    d.rectangle((0, 0, int(w * 0.018), h), fill="#214C6D")
    for x in range(int(w * 0.11), w, max(96, int(w * 0.12))):
        d.line((x, 0, x, h), fill="#E4ECF2", width=1)
    for y in range(int(h * 0.09), h, max(96, int(h * 0.07))):
        d.line((0, y, w, y), fill="#E8EFF5", width=1)
    d.rectangle((int(w * 0.018), 0, int(w * 0.021), h), fill="#67A6B8")
    return img


def _daily_digest_project_root() -> str:
    try:
        here = os.path.dirname(os.path.abspath(__file__))
        candidates = [
            here,
            os.path.dirname(here),
            os.path.dirname(os.path.dirname(here)),
            os.getcwd(),
        ]
        for base in candidates:
            if base and os.path.exists(os.path.join(base, "assets", "logos")):
                return base
        return here
    except Exception:
        return os.getcwd()


def _daily_digest_normalize_relay_base_url(value: str = "") -> str:
    base_url = str(value or "").strip() or str(globals().get("DEFAULT_FOREIGN_MODEL_BASE_URL", "https://greatwalllink.top/v1"))
    base_url = base_url.replace("greatwallink.top", "greatwalllink.top").rstrip("/")
    if not base_url.endswith("/v1"):
        base_url = base_url + "/v1"
    return base_url


def _daily_digest_prepare_relay_env(logger=print) -> str:
    """Ensure daily digest uses the shared foreign-model relay without exposing keys."""
    current = os.environ.get("NEWAPI_BASE_URL", "") or os.environ.get("FOREIGN_MODEL_BASE_URL", "")
    candidates = []
    root = _daily_digest_project_root()
    for name in ("relay_settings.json", "gui_settings.json"):
        candidates.append(os.path.join(root, name))
        candidates.append(os.path.join(os.getcwd(), name))
    base_url = current
    if not base_url:
        for path in candidates:
            try:
                if not path or not os.path.exists(path):
                    continue
                data = json.loads(open(path, "r", encoding="utf-8").read())
                if isinstance(data, dict):
                    base_url = data.get("newapi_base_url") or data.get("foreign_base_url") or ""
                    if base_url:
                        break
            except Exception:
                continue
    base_url = _daily_digest_normalize_relay_base_url(base_url)
    os.environ["NEWAPI_BASE_URL"] = base_url
    os.environ.setdefault("FOREIGN_MODEL_BASE_URL", base_url)
    if logger:
        try:
            logger(f"🔌 每日研究速递中转站：{base_url}")
        except Exception:
            pass
    return base_url


def _daily_digest_read_secret_file(path: str) -> str:
    try:
        if path and os.path.exists(path):
            value = open(path, "r", encoding="utf-8").read()
            sanitizer = globals().get("sanitize_openai_api_key")
            return sanitizer(value) if callable(sanitizer) else re.sub(r"\s+", "", str(value or "").strip().strip('"\''))
    except Exception:
        return ""
    return ""


def _daily_digest_load_image_api_key() -> str:
    """Prefer the relay image key file used by the zhuzuo project, then fall back to OpenAI key."""
    for env_name in ("IMAGE_API_KEY", "OPENAI_IMAGE_API_KEY"):
        value = os.environ.get(env_name, "")
        sanitizer = globals().get("sanitize_openai_api_key")
        value = sanitizer(value) if callable(sanitizer) else re.sub(r"\s+", "", str(value or "").strip().strip('"\''))
        if value:
            return value
    root = _daily_digest_project_root()
    for path in (
        os.path.join(root, "image_api_key.txt"),
        os.path.join(os.getcwd(), "image_api_key.txt"),
        os.path.join(root, "openai_image_api_key.txt"),
        os.path.join(os.getcwd(), "openai_image_api_key.txt"),
    ):
        value = _daily_digest_read_secret_file(path)
        if value:
            return value
    return load_openai_api_key()


def _daily_digest_logo_path(lang: str = "zh") -> str:
    rel = "assets/logos/zh/logo_zh_tight.png" if str(lang).lower() in {"zh", "cn"} else "assets/logos/en/logo_en_tight.png"
    return os.path.join(_daily_digest_project_root(), rel)


def _daily_digest_paste_logo(img, *, lang: str = "zh", center_x: int | None = None, x: int | None = None, y: int = 90, target_h: int = 58, max_w: int | None = None, opacity: int = 245) -> bool:
    try:
        from PIL import Image
        with Image.open(_daily_digest_logo_path(lang)) as opened:
            logo = opened.convert("RGBA")
        ow, oh = logo.size
        scale = float(target_h) / max(1, float(oh))
        if max_w and ow * scale > max_w:
            scale = float(max_w) / max(1, float(ow))
        nw, nh = max(1, int(round(ow * scale))), max(1, int(round(oh * scale)))
        logo = logo.resize((nw, nh), Image.Resampling.LANCZOS)
        if opacity < 255:
            r, g, b, a = logo.split()
            a = a.point(lambda v: int(round(v * max(0, min(255, opacity)) / 255.0)))
            logo = Image.merge("RGBA", (r, g, b, a))
        px = int(round(center_x - nw / 2)) if center_x is not None else int(x or 0)
        base = img.convert("RGBA")
        base.alpha_composite(logo, dest=(px, int(y)))
        img.paste(base.convert("RGB"))
        return True
    except Exception:
        return False


def _daily_digest_draw_text_logo(draw, w: int, y: int = 90, *, center: bool = True, size: int = 50):
    font = _daily_digest_font(size, weight=800)
    text = "全澜脑科学®"
    tw = draw.textbbox((0, 0), text, font=font)[2]
    x = ((w - tw) // 2) if center else 78
    draw.text((x, y), text, font=font, fill="#1F3A5F")


def _daily_digest_draw_brand_header(img, draw, *, y: int = 86, centered: bool = True, compact: bool = False):
    w, _h = img.size
    if centered:
        ok = _daily_digest_paste_logo(img, lang="zh", center_x=w // 2, y=y, target_h=52 if compact else 64, max_w=int(w * 0.66), opacity=246)
        if not ok:
            _daily_digest_draw_text_logo(draw, w, y=y, center=True, size=46 if compact else 56)
        en = "QuanLan BrainScience®"
        font = _daily_digest_font(24 if compact else 28, weight=500)
        tw = draw.textbbox((0, 0), en, font=font)[2]
        draw.text(((w - tw) // 2, y + (62 if compact else 78)), en, font=font, fill="#607893")
    else:
        ok = _daily_digest_paste_logo(img, lang="zh", x=78, y=y, target_h=40 if compact else 44, max_w=310, opacity=246)
        if not ok:
            _daily_digest_draw_text_logo(draw, w, y=y, center=False, size=36 if compact else 38)
        draw.text((78, y + (50 if compact else 54)), "QuanLan BrainScience®", font=_daily_digest_font(22 if compact else 23, weight=500), fill="#607893")


def _daily_digest_text_width(draw, text: str, font) -> int:
    try:
        box = draw.textbbox((0, 0), str(text), font=font)
        return int(box[2] - box[0])
    except Exception:
        return 0


def _daily_digest_center_text(draw, text: str, y: int, font, fill: str, w: int = 1080):
    x = max(0, (w - _daily_digest_text_width(draw, text, font)) // 2)
    draw.text((x, y), text, font=font, fill=fill)


def _daily_digest_fit_center_text(draw, text: str, y: int, *, max_width: int, min_size: int, max_size: int, fill: str, canvas_w: int, weight: int = 900) -> tuple[int, int]:
    text = str(text or "")
    font = _daily_digest_font(max_size, weight=weight)
    for size in range(max_size, min_size - 1, -2):
        candidate = _daily_digest_font(size, weight=weight)
        if _daily_digest_text_width(draw, text, candidate) <= max_width:
            font = candidate
            break
    x = max(0, (canvas_w - _daily_digest_text_width(draw, text, font)) // 2)
    draw.text((x, y), text, font=font, fill=fill)
    try:
        bbox = draw.textbbox((x, y), text, font=font)
        return bbox[3], getattr(font, "size", max_size)
    except Exception:
        return y + getattr(font, "size", max_size), getattr(font, "size", max_size)


def _daily_digest_box(size: tuple[int, int], ratios: tuple[float, float, float, float]) -> tuple[int, int, int, int]:
    w, h = size
    x1, y1, x2, y2 = ratios
    return int(w * x1), int(h * y1), int(w * x2), int(h * y2)


def _daily_digest_draw_soft_panel(draw, box, *, radius: int = 22, fill: str = "#FFFFFF", outline: str = "#D7E3EC", width: int = 1):
    x1, y1, x2, y2 = [int(v) for v in box]
    draw.rounded_rectangle((x1, y1, x2, y2), radius=radius, fill=fill, outline=outline, width=width)


def _daily_digest_draw_magazine_rule(draw, x1: int, y: int, x2: int, *, accent: str = "#2F89A8", hairline: str = "#BFD0DD"):
    draw.line((x1, y, x2, y), fill=hairline, width=1)
    draw.line((x1, y, min(x2, x1 + max(70, int((x2 - x1) * 0.22))), y), fill=accent, width=4)


def _daily_digest_draw_fit_box(
    draw,
    text: str,
    box,
    *,
    min_size: int,
    max_size: int,
    weight: int = 800,
    fill: str = "#102A50",
    max_lines: int = 3,
    align: str = "left",
    line_gap_ratio: float = 0.20,
) -> int:
    x1, y1, x2, y2 = [int(v) for v in box]
    max_width = max(1, x2 - x1)
    max_height = max(1, y2 - y1)
    if max_lines <= 1:
        text = str(text or "").strip()
        font = _daily_digest_font(min_size, weight=weight)
        for size in range(max_size, min_size - 1, -2):
            candidate = _daily_digest_font(size, weight=weight)
            if _daily_digest_text_width(draw, text, candidate) <= max_width:
                font = candidate
                break
        try:
            bbox = draw.textbbox((0, 0), text, font=font)
            text_w = bbox[2] - bbox[0]
            text_h = bbox[3] - bbox[1]
        except Exception:
            text_w = _daily_digest_text_width(draw, text, font)
            text_h = getattr(font, "size", min_size)
        if align == "center":
            tx = x1 + max(0, (max_width - text_w) // 2)
        elif align == "right":
            tx = x2 - text_w
        else:
            tx = x1
        ty = y1 + max(0, (max_height - text_h) // 2)
        draw.text((tx, ty), text, font=font, fill=fill)
        return ty + text_h
    font, lines, line_gap, height = _daily_digest_fit_wrapped_text(
        draw,
        text,
        max_width=max_width,
        max_height=max_height,
        min_size=min_size,
        max_size=max_size,
        weight=weight,
        max_lines=max_lines,
    )
    line_gap = max(4, int(getattr(font, "size", max_size) * line_gap_ratio))
    height = _daily_digest_lines_height(draw, lines, font, line_gap=line_gap)
    start_y = y1 + max(0, (max_height - height) // 2)
    return _daily_digest_draw_lines(draw, lines, (x1, start_y), font, fill, max_width, line_gap=line_gap, align=align)


def _daily_digest_draw_meta_pill(draw, box, text: str, *, accent: str = "#2F89A8"):
    x1, y1, x2, y2 = [int(v) for v in box]
    font = _daily_digest_font(max(18, int((y2 - y1) * 0.42)), weight=800)
    draw.rounded_rectangle((x1, y1, x2, y2), radius=max(10, int((y2 - y1) / 2)), fill="#FFFFFF", outline="#C8D9E7", width=1)
    draw.rounded_rectangle((x1 + 8, y1 + 8, x1 + max(24, int((x2 - x1) * 0.05)), y2 - 8), radius=8, fill=accent)
    label = _daily_digest_display_meta(text, 90)
    tw = _daily_digest_text_width(draw, label, font)
    tx = max(x1 + 34, x1 + (x2 - x1 - tw) // 2)
    ty = y1 + max(0, (y2 - y1 - (draw.textbbox((0, 0), label, font=font)[3])) // 2) - 2
    draw.text((tx, ty), label, font=font, fill="#31506B")


def _daily_digest_article_journal_date(source: dict) -> str:
    journal = _daily_digest_display_meta(source.get("journal", ""), 54)
    date = _daily_digest_display_meta(source.get("pub_date", ""), 24)
    parts = []
    if journal:
        parts.append(f"《{journal}》")
    if date:
        parts.append(date)
    return " · ".join(parts)


def _daily_digest_draw_rule(draw, x1: int, y: int, x2: int, *, fill: str = "#C8D9E7", width: int = 2):
    draw.line((x1, y, x2, y), fill=fill, width=width)


def _daily_digest_draw_pill(draw, xyxy, text: str, *, fill: str = "#E6F0F8", outline: str = "#C8D9E7", text_fill: str = "#315B7F", font=None):
    x1, y1, x2, y2 = xyxy
    font = font or _daily_digest_font(24, weight=700)
    draw.rounded_rectangle((x1, y1, x2, y2), radius=max(12, int((y2 - y1) / 2)), fill=fill, outline=outline, width=1)
    bbox = draw.textbbox((0, 0), text, font=font)
    tx = x1 + max(0, (x2 - x1 - (bbox[2] - bbox[0])) // 2)
    ty = y1 + max(0, (y2 - y1 - (bbox[3] - bbox[1])) // 2) - 2
    draw.text((tx, ty), text, font=font, fill=text_fill)


def _daily_digest_draw_evidence_row(draw, label: str, text: str, *, x: int, y: int, max_width: int, max_lines: int = 2) -> int:
    label_font = _daily_digest_font(22, weight=900)
    text_font = _daily_digest_font(25, weight=600)
    draw.rounded_rectangle((x, y + 2, x + 112, y + 43), radius=11, fill="#E6F0F8", outline="#C8D9E7", width=1)
    draw.text((x + 17, y + 8), label, font=label_font, fill="#315B7F")
    bottom = _daily_digest_draw_wrapped(
        draw,
        _daily_digest_display_text(text, 260),
        (x + 138, y),
        text_font,
        "#1D2B44",
        max_width - 138,
        line_gap=5,
        max_lines=max_lines,
    )
    return max(bottom + 8, y + 54)


def _daily_digest_source_meta(source: dict) -> str:
    parts = []
    if source.get("journal"):
        parts.append(_daily_digest_display_meta(source.get("journal")))
    if source.get("pub_date"):
        parts.append(_daily_digest_display_meta(source.get("pub_date")))
    if source.get("doi"):
        parts.append("DOI: " + str(source.get("doi")))
    elif source.get("pmid"):
        parts.append("PMID: " + str(source.get("pmid")))
    return " · ".join(parts)


def _daily_digest_digest_count_label(digest: dict) -> str:
    count = len(digest.get("articles", []) or [])
    return f"{count} 篇文献"


def _daily_digest_primary_title(digest: dict) -> str:
    articles = digest.get("articles", []) or []
    if not articles:
        return ""
    first = articles[0]
    source = first.get("source", {}) or {}
    return _daily_digest_display_text(first.get("title_cn") or source.get("title", ""), 120)


def _daily_digest_catalog_authors(source: dict, max_chars: int = 150) -> str:
    authors = _daily_digest_display_meta(source.get("authors", ""), max_chars)
    return authors or "作者信息待补全"


DAILY_DIGEST_TERM_EXPLANATIONS = {
    "图式": "图式（组织经验和知识的抽象框架）",
    "连接主义": "连接主义（用网络连接解释认知的理论）",
    "陈述性记忆": "陈述性记忆（可有意识回忆的事实和事件记忆）",
    "表征": "表征（信息在大脑或模型中的表示方式）",
    "先验": "先验（已有知识或预期）",
    "跨尺度": "跨尺度（从细胞、环路到行为）",
}


def _daily_digest_explain_terms_once(text: str) -> str:
    value = str(text or "")
    for term, explained in DAILY_DIGEST_TERM_EXPLANATIONS.items():
        if term in value and explained not in value:
            value = value.replace(term, explained, 1)
    return value


def _daily_digest_polish_science_text(text: str, max_chars: int = 420) -> str:
    value = _daily_digest_display_text(text, max_chars)
    if not value:
        return ""
    replacements = {
        "AqRP": "AgRP",
        "Agrp": "AgRP",
        "agrp": "AgRP",
        "Sim-2": "Sim2",
        "sim2": "Sim2",
        "下丘脑旁室核": "下丘脑室旁核",
    }
    for old, new in replacements.items():
        value = value.replace(old, new)
    value = re.sub(r"研究聚焦这项研究想弄清[，,]?", "这项研究想弄清", value)
    value = re.sub(r"研究聚焦(?:于|的是|是)?", "", value)
    value = re.sub(r"研究结合了研究(?:在|中|通过)?", "研究在", value)
    value = re.sub(r"研究采用研究(?:对|在|中|通过)?", "研究", value)
    value = re.sub(r"研究采用研究", "研究采用", value)
    value = re.sub(r"研究结合了(?=研究)", "", value)
    value = re.sub(r"研究发现[，,:：]?发现[，,:：]?", "研究发现，", value)
    value = re.sub(r"发现[，,:：]?发现[，,:：]?", "发现，", value)
    if re.search(r"(?:神经元|表面蛋白|内吞|突触)", value):
        value = re.sub(r"建立和维持连接", "建立和维持神经元之间的连接", value)
        value = re.sub(r"建立或维持连接", "建立或维持神经元之间的连接", value)
        value = re.sub(r"建立、维持连接", "建立、维持神经元之间的连接", value)
        value = re.sub(r"维持连接(?=[？?。.!！；;，,]|$)", "维持神经元之间的连接", value)
    value = re.sub(r"(?<!到)定位(?=[A-Za-z0-9\u4e00-\u9fff])", "定位到", value)
    value = re.sub(r"由此得到的结论是", "论文给出的结论是", value)
    value = re.sub(r"由此看[，,:：]?", "这些结果支持这样的判断：", value)
    value = re.sub(r"证明了", "支持了", value)
    value = re.sub(r"([^。；;，,]{2,24})主动提供了?新的研究角度", r"这些结果提示，\1值得在后续研究中关注", value)
    value = re.sub(r"([^。；;，,]{2,24})提供了?新的研究角度", r"这些结果提示，\1值得在后续研究中关注", value)
    value = re.sub(r"(?:有望|可能)?(?:突破|颠覆|重塑)(?:[^。；;，,]{0,12})", "仍需在后续研究中验证", value)
    value = re.sub(r"(?:改变|扭转)这一局面", "仍需进一步验证", value)
    value = re.sub(r"提供了?新思路", "提出了可继续检验的问题", value)
    value = re.sub(r"提供了?新的研究角度", "提示该机制值得进一步分析", value)
    value = re.sub(r"提供了?重要线索", "提供了具体的机制线索", value)
    value = re.sub(r"具有重大意义", "有助于理解相关机制", value)
    value = re.sub(r"具有重要意义", "有助于理解相关机制", value)
    value = re.sub(r"(机制线索)(有助于)", r"\1，\2", value)
    value = re.sub(r"这有助于这(?:有助于)?", "这有助于", value)
    value = re.sub(r"有助于这有助于", "有助于", value)
    value = re.sub(r"这让我们更清楚地理解(?:这有助于|有助于)", "这有助于", value)
    value = re.sub(r"为.*?带来希望", "仍需进一步验证", value)
    value = re.sub(r"可能改变临床实践", "仍需进一步临床验证", value)
    value = re.sub(r"证明了疗效", "提供了疗效相关的初步证据", value)
    value = _daily_digest_explain_terms_once(value)
    value = _daily_digest_clean_aiish_science_phrase(value)
    value = re.sub(r"\s+", " ", value).strip()
    return value


def _daily_digest_clean_aiish_science_phrase(text: str) -> str:
    value = str(text or "")
    if not value:
        return ""
    value = re.sub(r"这有助于理解这(?:有助于|为|提示)?", "这有助于", value)
    value = re.sub(r"这有助于理解(?:解析|理解|说明)", "这有助于解释", value)
    value = re.sub(r"这有助于理解(该图谱|该工具|该传感器|该模型)为理解", r"\1有助于理解", value)
    value = re.sub(r"这有助于理解为理解", "这有助于理解", value)
    value = re.sub(r"这有助于理解(.{0,18})提供(?:了)?", r"\1提供了", value)
    value = re.sub(r"^(该图谱|该工具|该传感器|该模型|该方法|这一结果)为理解(.{2,40})提供了(.{2,40})$", r"\1提供了理解\2的\3", value)
    value = re.sub(r"^为理解(.{2,40})提供了(.{2,40})$", r"这提供了理解\1的\2", value)
    value = re.sub(r"提供了理解(.{2,40})的分子层面的系统性证据", r"从分子层面支持了对\1的理解", value)
    value = re.sub(r"提供了理解(.{2,40})的初步证据", r"为分析\1提供了初步证据", value)
    value = re.sub(r"这提供了理解(.{2,40})的初步证据", r"这为分析\1提供了初步证据", value)
    value = re.sub(r"为后续研究提供依据", "提示该问题值得进一步验证", value)
    value = re.sub(r"为理解(.{2,40})提供了?摘要层面的证据", r"支持论文关于\1的判断", value)
    value = re.sub(r"研究方法是[：:]?", "", value)
    value = re.sub(r"研究结果是[：:]?", "", value)
    value = re.sub(r"方法上[，,:：]?", "", value)
    value = re.sub(r"结果发现[，,:：]?", "", value)
    value = re.sub(r"研究据此认为[，,:：]?", "", value)
    value = re.sub(r"([。！？!?])这篇论文发表于", r"\1这篇论文发表于", value)
    value = re.sub(r"(等)+人", "等人", value)
    value = re.sub(r"由([^。]{1,80})等等人完成", r"由\1等人完成", value)
    value = re.sub(r"主要来自([^。；;]{2,80})和\1", r"主要来自\1", value)
    value = re.sub(r"([。！？!?]){2,}", r"\1", value)
    value = re.sub(r"\s+", " ", value).strip()
    return value


def _daily_digest_split_long_cn_sentences(text: str, max_len: int = 42) -> str:
    value = str(text or "").strip()
    if not value:
        return ""
    value = re.sub(r"(神经元|细胞|通路|环路|脑区|变量|结构|机制)及其对", r"\1。同时分析其对", value)
    value = re.sub(r"(神经元|细胞|通路|环路|脑区|变量|结构|机制)及其在", r"\1。同时分析其在", value)
    chunks = re.split(r"([。！？!?])", value)
    sentences = []
    for idx in range(0, len(chunks), 2):
        body = (chunks[idx] or "").strip()
        punct = chunks[idx + 1] if idx + 1 < len(chunks) else ""
        if not body:
            continue
        if len(body) <= max_len:
            sentences.append(body + (punct or "。"))
            continue
        clauses = [x.strip(" ，,；;：:") for x in re.split(r"[，,；;]", body) if x.strip(" ，,；;：:")]
        if len(clauses) <= 1:
            sentences.append(body + (punct or "。"))
            continue
        current = ""
        for clause in clauses:
            if current and len(current) + len(clause) + 1 > max_len:
                sentences.append(current.rstrip("，,；;：:") + "。")
                current = clause
            else:
                current = f"{current}，{clause}" if current else clause
        if current:
            sentences.append(current.rstrip("，,；;：:") + (punct or "。"))
    return "".join(sentences)


def _daily_digest_voice_sentence(text: str, max_chars: int = 300) -> str:
    value = _daily_digest_polish_science_text(text, max_chars)
    if not value:
        return ""
    if re.search(r"[？?]$", value):
        return value
    if re.search(r"[。.!！]$", str(text or "").strip()) and not re.search(r"[。.!！]$", value):
        value += "。"
    elif not re.search(r"[。.!！]$", value):
        value += "。"
    return _daily_digest_split_long_cn_sentences(value, max_len=42)


def _daily_digest_strip_tail_punctuation(text: str) -> str:
    return re.sub(r"[\s。．.!！?？;；,，、:：]+$", "", _daily_digest_polish_science_text(text, 420)).strip()


def _daily_digest_brief_authors_for_voice(value: str) -> str:
    text = _daily_digest_display_meta(value, 180)
    text = re.sub(r"\s+et\s+al\.?", " et al.", text, flags=re.I)
    parts = [x.strip() for x in re.split(r"[,，;；、]+", text) if x.strip()]
    if not parts:
        return "作者信息待补全"
    author = parts[-1]
    author = re.sub(r"\s+et\s+al\.?$", "", author, flags=re.I).strip()
    author = re.sub(r"(?:等人)+$", "", author).strip()
    return f"{author}等人"


def _daily_digest_brief_affiliations_for_voice(value: str) -> str:
    text = _daily_digest_clean_affiliation(value, 180)
    if not text:
        return "机构信息待补全"
    parts = [x.strip() for x in re.split(r"[;；]+", text) if x.strip()]
    cleaned = []
    for part in parts[:2]:
        part = re.sub(r"\bDepartment of\b|\bSchool of\b|\bFaculty of\b|\bDivision of\b", "", part, flags=re.I)
        part = re.sub(r"\bInstitute for\b", "Institute of", part, flags=re.I)
        part = _daily_digest_clean_affiliation(part, 90)
        part = re.sub(r"(霍华德·休斯医学研究所)[，,、;；].*", r"\1", part)
        part = re.sub(r"(北京大学|清华大学|复旦大学|耶鲁大学|哥伦比亚大学|华盛顿大学|苏黎世联邦理工学院|斯坦福大学|哈佛医学院)[^和与、，,;；]{0,40}", r"\1", part)
        part = re.sub(r"\s+", " ", part).strip(" ,，")
        if part:
            cleaned.append(_daily_digest_display_meta(part, 72))
    if not cleaned:
        return "机构信息待补全"
    if len(cleaned) == 1:
        return cleaned[0]
    return "和".join(cleaned[:2])


def _daily_digest_citation_sentence(source: dict, title: str, authors: str, affiliation: str) -> str:
    journal = _daily_digest_display_meta(source.get("journal", ""), 80)
    brief_authors = _daily_digest_brief_authors_for_voice(authors)
    brief_affiliation = _daily_digest_brief_affiliations_for_voice(affiliation)
    prefix = f"这篇论文发表于《{journal}》" if journal else "这篇论文"
    if title:
        prefix += f"，题为《{title}》"
    return f"{prefix}，由{brief_authors}完成，主要来自{brief_affiliation}。"


def _daily_digest_one_question(text: str) -> str:
    value = _daily_digest_strip_tail_punctuation(text)
    if not value:
        return ""
    parts = re.split(r"[？?]+", value)
    first = (parts[0] or "").strip(" ，,；;：:")
    if not first:
        return ""
    return first + "？"


def _daily_digest_clean_question_seed(text: str) -> str:
    value = _daily_digest_strip_tail_punctuation(text)
    if not value:
        return ""
    value = re.sub(r"为(?:后续|未来|进一步)?研究提供(?:依据|线索|思路|参考)[，,、]?", "", value)
    value = re.sub(r"为(?:后续|未来|进一步)?(?:研究|验证)(?:提供|奠定|打下)(?:依据|线索|基础|参考)[，,、]?", "", value)
    value = re.sub(r"提供了?(?:依据|线索|思路|角度|参考)[，,、]?", "", value)
    value = re.sub(r"通过(.{0,28})(?:提供依据|提供线索|提供思路)", r"通过\1发挥作用", value)
    value = re.sub(r"为后续研究提供依据", "", value)
    value = re.sub(r"提供了?机制线索", "", value)
    return value.strip(" ，,；;：:。")


def _daily_digest_hook_question(text: str, fallback: str = "") -> str:
    value = _daily_digest_clean_question_seed(text)
    value = re.sub(r"^(?:该研究|这项研究|研究|研究者|本文|作者|团队)\s*(?:旨在|想回答的是|想弄清|解析|探讨|关注|聚焦于?|试图说明|要回答)?[，,:：\s]*", "", value)
    value = re.sub(r"^(?:解析|探讨|说明|回答|关注|聚焦|描述|评估)\s*", "", value)
    value = re.sub(r"^(?:结果|证据|实验)\s*(?:显示|提示|表明)[，,:：\s]*", "", value)
    value = re.sub(r"^(?:如何|为什么|为何|什么|哪一类|哪些|谁|怎样)", lambda m: m.group(0), value)
    value = value.strip(" ，,；;：:")
    if not value:
        value = _daily_digest_clean_question_seed(fallback)
    if not value:
        return ""
    if re.search(r"[？?]$", value):
        return _daily_digest_one_question(value)
    if re.search(r"(?:疼痛|痛觉)", value) and re.search(r"(?:迷走神经|脑干|孤束核|导水管周围灰质)", value):
        return "治疗疼痛时，为什么要关注迷走神经通向脑干的路径？"
    if re.search(r"(?:内吞|endocyt|表面蛋白|surface protein)", value, flags=re.I):
        if re.search(r"(?:突触|连接|connect)", value, flags=re.I):
            return "神经元如何通过内吞作用调控表面蛋白，并影响突触连接？"
        return "神经元如何通过内吞作用调控细胞表面蛋白？"
    if re.search(r"(?:疼痛|痛觉|负性情感|情绪)", value):
        return "为什么有些疼痛不只是身体信号，还会影响情绪？"
    if re.search(r"(?:AgRP|饥饿|禁食|下丘脑|能量)", value):
        return "饥饿感会不会在真正缺能量之前，就被大脑提前预演？"
    if re.search(r"(?:类器官|中脑|后脑|细胞类型|形态发生)", value):
        return "为什么脑类器官需要先搭出更接近真实发育的细胞地图？"
    if re.search(r"(?:AI|人工智能|大语言模型|图式|记忆|知识)", value, flags=re.I):
        return "当 AI 开始整理脑科学知识，记忆理论会被怎样重新提问？"
    if re.search(r"(?:如何|怎么|怎样|为什么|为何|能否|是否|会不会|是什么|有什么|哪一)", value):
        return _daily_digest_one_question(value + "？")
    return _daily_digest_one_question(f"{value}为什么重要？")


def _daily_digest_voiceover_with_hook(item: dict) -> str:
    source = item.get("source", {}) or {}
    hook = _daily_digest_hook_question(
        item.get("research_question") or item.get("hook", ""),
        item.get("key_finding") or source.get("title") or source.get("abstract", ""),
    )
    if not hook:
        return str(item.get("voiceover", "") or "").strip()
    title = _daily_digest_display_text(item.get("title_cn") or source.get("title", ""), 120)
    authors = _daily_digest_display_meta(item.get("authors_cn") or source.get("authors", ""), 120) or "作者信息待补全"
    affiliation = _daily_digest_clean_affiliation(item.get("affiliation_cn") or source.get("affiliations", "")) or "机构信息待补全"
    method = _daily_digest_clean_evidence_phrase(item.get("evidence_path") or _daily_digest_infer_evidence_path(source))
    finding = _daily_digest_strip_tail_punctuation(item.get("key_finding", ""))
    conclusion = _daily_digest_strip_tail_punctuation(item.get("conclusion_cn", ""))
    meaning = _daily_digest_strip_tail_punctuation(item.get("why_it_matters", ""))
    scope = _daily_digest_strip_tail_punctuation(item.get("scope_note") or _daily_digest_infer_scope_note(source))

    sentences = [hook]
    if method:
        method = re.sub(r"^(?:研究)?(?:结合了|结合|采用|使用|通过)\s*", "", method)
        if finding:
            finding = re.sub(r"^(?:主要发现是|核心发现是|结果显示|发现|研究发现)\s*[，,:：]?\s*", "", finding)
            sentences.append(_daily_digest_method_sentence(method))
            sentences.append(f"结果显示，{finding}。")
            finding = ""
        else:
            sentences.append(_daily_digest_method_sentence(method))
    if finding:
        finding = re.sub(r"^(?:主要发现是|核心发现是|结果显示|发现|研究发现)\s*[，,:：]?\s*", "", finding)
        sentences.append(f"结果显示，{finding}。")
    if conclusion:
        conclusion = re.sub(r"^(?:结论是|研究结论是|这些结果(?:支持|提示)?)[，,:：]?\s*", "", conclusion)
        sentences.append(f"{conclusion}。")
    elif finding:
        sentences.append(f"这些结果支持论文提出的机制解释。")
    if meaning:
        meaning = re.sub(r"^(?:这说明|这一结果说明|研究意义是)[，,:：]?\s*", "", meaning)
        meaning = re.sub(r"^(?:它|该研究|这一结果|这有助于|有助于)", "", meaning).strip(" ，,")
        if meaning:
            if re.search(r"^(?:解释|说明|理解)", meaning):
                sentences.append(f"这有助于{meaning}。")
            elif re.search(r"^(?:这为|为|帮助|支持|提供|提示)", meaning):
                sentences.append(f"{meaning}。")
            else:
                sentences.append(_daily_digest_meaning_sentence(meaning))
    if scope:
        scope = re.sub(r"^理解这一结论时还要注意[，,:：]?\s*", "", scope)
        sentences.append(f"需要注意的是，{scope}。")
    sentences.append(_daily_digest_citation_sentence(source, title, authors, affiliation))
    return "".join(_daily_digest_voice_sentence(s, 300) for s in sentences if s)


def _daily_digest_normalize_article_copy(item: dict) -> dict:
    source = item.get("source", {}) or {}
    hook = _daily_digest_hook_question(
        item.get("research_question") or item.get("hook", ""),
        item.get("key_finding") or source.get("title") or source.get("abstract", ""),
    )
    if hook:
        item["research_question"] = hook
    for key, limit in (
        ("title_cn", 140),
        ("evidence_path", 220),
        ("key_finding", 260),
        ("conclusion_cn", 220),
        ("why_it_matters", 220),
        ("scope_note", 220),
    ):
        if item.get(key):
            item[key] = _daily_digest_strip_tail_punctuation(_daily_digest_clean_aiish_science_phrase(item.get(key)))
            item[key] = _daily_digest_display_text(item[key], limit)
    item["affiliation_cn"] = _daily_digest_clean_affiliation(item.get("affiliation_cn") or source.get("affiliations", "")) or "机构信息待补全"
    if item.get("authors_cn"):
        item["authors_cn"] = _daily_digest_display_meta(item.get("authors_cn"), 140)
    return item


def _daily_digest_copy_quality_warnings(text: str) -> list[str]:
    value = str(text or "")
    checks = [
        (r"这有助于这|有助于这有助于|为理解.*为理解", "重复意义连接"),
        (r"研究方法是|研究结果是|方法上|结果发现|研究据此认为", "机械摘要模板"),
        (r"为后续研究提供依据|提供新思路|提供新的研究角度|重大意义|重要意义", "空泛价值表达"),
        (r"突破|颠覆|重塑|改变局面|带来希望", "过度拔高"),
        (r"等等人|等人等人", "作者表述重复"),
        (r"电子邮箱|Electronic address|CA \\d|\\bUSA\\b|\\bUnited States\\b", "机构信息冗余"),
        (r"建立和维持连接", "连接对象不清"),
    ]
    return [label for pattern, label in checks if re.search(pattern, value, flags=re.I)]


def _daily_digest_method_sentence(method: str) -> str:
    value = _daily_digest_clean_evidence_phrase(method)
    if not value:
        return ""
    value = re.sub(r"^(?:研究)?(?:结合了|结合|采用|使用|通过)\s*", "", value)
    if re.match(r"^(?:在|对|以|用|利用|基于|通过|采用|结合|比较|测量|标记|操控)", value):
        return f"研究{value}。"
    if re.match(r"^(?:设计|开发|构建|绘制|建立|筛选|验证|分析|评估|测试|优化)", value):
        return f"研究{value}。"
    return f"研究围绕{value}展开。"


def _daily_digest_meaning_sentence(meaning: str) -> str:
    value = _daily_digest_strip_tail_punctuation(meaning)
    value = re.sub(r"^(?:它|该研究|这一结果|这些结果|这有助于|有助于)", "", value).strip(" ，,")
    if not value:
        return ""
    value = _daily_digest_clean_aiish_science_phrase(value)
    if re.search(r"^(?:该图谱|该工具|该传感器|该模型|该方法|这一结果|这提供了)", value):
        return f"{value}。"
    if re.search(r"^(?:解释|说明|理解|解析)", value):
        return f"这有助于{value}。"
    if re.search(r"^(?:某一|相关|该|这种|这一|这些)?(?:机制|环路|细胞|模型|图谱|工具|方法|传感器|病理|信号|过程)", value):
        return f"这有助于解释{value}。"
    if re.search(r"(?:机制|环路|细胞|模型|图谱|工具|方法|传感器|病理|信号|过程)", value):
        return f"这有助于把握{value}。"
    return f"这为理解相关问题提供了具体信息。"


def _daily_digest_clean_evidence_phrase(text: str) -> str:
    value = _daily_digest_strip_tail_punctuation(text)
    value = re.sub(r"^(?:证据链|证据路径|研究依据|依据|证据)\s*(?:来自|为|是|：|:)?\s*", "", value)
    value = re.sub(r"^(?:研究者|研究团队|作者|团队)\s*(?=在|通过|利用|结合|采用)", "", value)
    value = re.sub(r"^(?:研究)?(?:结合了|结合|采用|使用|通过)\s*", "", value)
    value = re.sub(r"^(小鼠|猕猴|动物)实验结合", r"在\1中结合", value)
    value = re.sub(r"^体外实验结合", "在体外实验中结合", value)
    value = re.sub(r"^(?:研究)?在", "在", value)
    value = re.sub(r"(?:构成|形成|提供)(?:的)?(?:[^，；;]{0,18})?证据$", "", value).strip(" ，,；;")
    value = re.sub(r"(?:的)?证据$", "", value).strip(" ，,；;")
    return value


def _daily_digest_evidence_finding_sentence(evidence: str, finding: str) -> str:
    evidence = _daily_digest_clean_evidence_phrase(evidence)
    finding = _daily_digest_strip_tail_punctuation(finding)
    finding = re.sub(r"^(?:主要发现是|核心发现是|结果显示|发现|研究发现)\s*[，,:：]?\s*", "", finding)
    if evidence and finding:
        return f"{_daily_digest_strip_tail_punctuation(_daily_digest_method_sentence(evidence))}。结果显示，{finding}"
    if finding:
        return finding
    if evidence:
        return _daily_digest_strip_tail_punctuation(_daily_digest_method_sentence(evidence))
    return ""


def _daily_digest_meaning_scope_paragraphs(meaning: str, scope: str) -> list[str]:
    meaning = _daily_digest_strip_tail_punctuation(meaning)
    scope = _daily_digest_strip_tail_punctuation(scope)
    paragraphs = []
    if meaning:
        meaning = re.sub(r"^(?:这说明|这一结果说明)[，,:：]?\s*", "", meaning)
        if re.search(r"^(?:这|它|该结果|这一结果|为|有助于|帮助|提供)", meaning):
            paragraphs.append(_daily_digest_clean_aiish_science_phrase(meaning))
        else:
            paragraphs.append(_daily_digest_strip_tail_punctuation(_daily_digest_meaning_sentence(meaning)))
    if scope:
        scope = re.sub(r"^理解这一结论时还要注意[，,:：]?\s*", "", scope)
        scope = re.sub(r"^(?:目前仍需注意|目前需要注意|仍需注意)[，,:：]?\s*", "", scope)
        paragraphs.append(f"需要注意的是，{scope}")
    return paragraphs


def _daily_digest_conclusion_sentence(conclusion: str, finding: str) -> str:
    conclusion = _daily_digest_strip_tail_punctuation(conclusion)
    if conclusion:
        conclusion = re.sub(r"^(?:结论是|研究结论是|这些结果(?:支持|提示)?)[，,:：]?\s*", "", conclusion)
        return f"这些结果支持这样的判断：{conclusion}"
    finding = _daily_digest_strip_tail_punctuation(finding)
    if finding:
        return "这些结果支持论文提出的机制解释"
    return ""


def _daily_digest_article_summary_paragraphs(item: dict) -> list[str]:
    source = item.get("source", {}) or {}
    question = _daily_digest_strip_tail_punctuation(item.get("research_question") or item.get("hook", ""))
    title = _daily_digest_display_text(item.get("title_cn") or source.get("title", ""), 120)
    authors = _daily_digest_display_meta(item.get("authors_cn") or source.get("authors", ""), 120) or "作者信息待补全"
    affiliation = _daily_digest_clean_affiliation(item.get("affiliation_cn") or source.get("affiliations", "")) or "机构信息待补全"
    evidence = _daily_digest_clean_evidence_phrase(item.get("evidence_path") or _daily_digest_infer_evidence_path(source))
    finding = _daily_digest_strip_tail_punctuation(item.get("key_finding", ""))
    conclusion = _daily_digest_strip_tail_punctuation(item.get("conclusion_cn", ""))
    meaning = _daily_digest_strip_tail_punctuation(item.get("why_it_matters", ""))
    scope = _daily_digest_strip_tail_punctuation(item.get("scope_note") or _daily_digest_infer_scope_note(source))
    parts = []
    if question:
        parts.append(_daily_digest_hook_question(question, item.get("key_finding") or source.get("title", "")))
    if finding:
        finding_card = re.sub(r"^(?:主要发现是|核心发现是|结果显示|发现|研究发现)\s*[，,:：]?\s*", "", finding)
        parts.append(f"研究发现，{finding_card}")
    elif evidence:
        parts.append(f"研究围绕{evidence}展开")
    conclusion_sentence = _daily_digest_conclusion_sentence(conclusion, finding)
    if conclusion_sentence:
        parts.append(conclusion_sentence)
    parts.extend(_daily_digest_meaning_scope_paragraphs(meaning, scope)[:1])
    if not parts:
        abstract = _daily_digest_strip_tail_punctuation(source.get("abstract", ""))
        if abstract:
            parts.append(abstract)
    cleaned = []
    for x in parts[:5]:
        x = _daily_digest_polish_science_text(x, 220)
        if x:
            cleaned.append(x)
    return cleaned


def _daily_digest_article_summary_paragraph(item: dict) -> str:
    return "\n".join(_daily_digest_article_summary_paragraphs(item))


def _daily_digest_visual_topic(item: dict) -> str:
    source = item.get("source", {}) or {}
    text = " ".join(
        str(x or "")
        for x in (
            item.get("title_cn"),
            item.get("research_question"),
            item.get("key_finding"),
            item.get("conclusion_cn"),
            source.get("title"),
            source.get("abstract"),
        )
    )
    concrete_candidates = [
        item.get("key_finding", ""),
        item.get("conclusion_cn", ""),
        item.get("research_question", ""),
        item.get("title_cn", ""),
        source.get("title", ""),
    ]
    for candidate in concrete_candidates:
        sentence = _daily_digest_visual_sentence(candidate, max_chars=30)
        if sentence and not _daily_digest_is_generic_visual_label(sentence):
            return sentence
    topic_rules = [
        (r"(?:迷走神经|vagus|VNS).*(?:疼痛|痛觉|pain)|(?:疼痛|痛觉|pain).*(?:迷走神经|vagus|VNS)", "迷走神经-脑干痛觉通路"),
        (r"(?:cNTS|孤束核).*(?:PAG|导水管周围灰质)|(?:PAG|导水管周围灰质).*(?:cNTS|孤束核)", "cNTS-PAG脑干通路"),
        (r"(?:类器官|organoid).*(?:中脑|后脑|midbrain|hindbrain)", "中脑与后脑类器官图谱"),
        (r"(?:AgRP|饥饿|禁食|下丘脑|能量)", "下丘脑能量预期环路"),
        (r"(?:肠道微生物|微生物|gut microbi|肠神经|雄激素)", "肠道微生物与肠神经信号"),
        (r"(?:深部脑刺激|DBS|白质|扣带束)", "深部脑刺激后的白质变化"),
        (r"(?:tau|APOE|阿尔茨海默|神经蛋白酶体)", "tau蛋白稳态与神经蛋白酶体"),
        (r"(?:内吞|endocyt|表面蛋白|surface protein).*(?:突触|连接|connect)|(?:突触|连接|connect).*(?:内吞|endocyt|表面蛋白|surface protein)", "内吞体图谱揭示神经元连接背后的细胞表面蛋白动态"),
    ]
    for pattern, topic in topic_rules:
        if re.search(pattern, text, flags=re.I):
            return topic
    title = _daily_digest_strip_tail_punctuation(item.get("title_cn") or source.get("title", ""))
    title = re.sub(r"^(?:关于|解析|探讨|研究)\s*", "", title)
    return _daily_digest_visual_sentence(title, max_chars=30) or "今日神经科学研究"


def _daily_digest_is_generic_visual_label(text: str) -> bool:
    value = re.sub(r"\s+", "", str(text or ""))
    generic = {
        "AI与脑科学知识整合",
        "与脑科学知识整合",
        "记忆图式与抽象知识",
        "今日神经科学研究",
        "脑科学知识整合",
        "AI如何重塑脑科学问题",
        "记忆理论中的抽象知识地图",
    }
    return value in generic


def _daily_digest_visual_sentence(text: str, *, max_chars: int = 42) -> str:
    value = _daily_digest_polish_science_text(text, 180)
    if not value:
        return ""
    value = re.sub(r"^(?:这项研究|该研究|研究者|研究|论文|文章)\s*(?:发现|显示|提示|表明|认为|据此认为|给出的结论是)?[，,:：\s]*", "", value)
    value = re.sub(r"^(?:结果|证据|实验|数据)\s*(?:发现|显示|提示|表明|支持)[，,:：\s]*", "", value)
    value = re.sub(r"^(?:研究发现|研究结果显示|主要发现是|核心发现是|结论是|论文给出的结论是)[，,:：\s]*", "", value)
    value = re.sub(r"^(?:这些结果|该结果|这一结果)\s*(?:支持|提示|表明)[，,:：\s]*", "", value)
    value = re.sub(r"^(?:这有助于|有助于|为|提供了|提示)[，,:：\s]*", "", value)
    value = re.sub(r"需要注意的是[，,:：]?", "", value)
    value = re.sub(r"可解析的", "", value)
    value = re.sub(r"同一条", "一条", value)
    value = re.sub(r"为理解.*?提供(?:了)?(?:机制)?线索", "", value)
    value = re.sub(r"[，,；;]\s*(?:并|并且|同时|还|以及|以)[^。！？!?；;，,]{0,28}(?:编|调|介|参|促|抑|改|影|连)$", "", value)
    value = re.sub(r"\s+", " ", value).strip(" ，,；;：:。")
    if not value:
        return ""
    known_rules = [
        (r"(?:cNTS|尾侧孤束核|孤束核).*(?:PAG|导水管周围灰质).*(?:迷走神经刺激|疼痛|痛觉)", "cNTS-PAG神经元参与迷走神经刺激的镇痛效应"),
        (r"(?:负性情感|负性情绪).*(?:疼痛|痛觉)|(?:疼痛|痛觉).*(?:负性情感|负性情绪)", "该通路也影响疼痛相关负性情绪"),
        (r"(?:单细胞|多组学).*(?:类器官|中脑|后脑)", "单细胞多组学图谱指导后部脑类器官工程"),
        (r"(?:形态发生因子|morphogen).*(?:细胞类型|神经元)", "形态发生因子筛选可扩展类器官细胞类型"),
        (r"(?:Sim2|AgRP).*(?:禁食|饥饿|能量)", "Sim2阳性下丘脑神经元可提前激活AgRP神经元"),
        (r"(?:肠道微生物|微生物).*(?:雄激素|肠道运动|肠神经)", "肠道微生物可通过雄激素信号影响肠神经功能"),
        (r"(?:深部脑刺激|DBS).*(?:白质|扣带束|髓鞘)", "深部脑刺激后可观察到白质微结构变化"),
        (r"(?:神经蛋白酶体|APOE|tau).*(?:成对螺旋丝|聚集|病理)", "神经蛋白酶体功能影响tau病理形成"),
    ]
    for pattern, replacement in known_rules:
        if re.search(pattern, value, flags=re.I):
            return replacement
    if len(value) <= max_chars:
        return value
    clauses = [x.strip(" ，,；;：:。") for x in re.split(r"[。；;]", value) if x.strip()]
    for clause in clauses:
        if len(clause) <= max_chars:
            return clause
        sub_clauses = [x.strip(" ，,；;：:。") for x in re.split(r"[，,]", clause) if x.strip()]
        if sub_clauses and len(sub_clauses[0]) <= max_chars:
            return sub_clauses[0]
    short = value[:max_chars].rstrip()
    short = re.sub(r"[，,、；;：:\s]*(?:和|及|以及|并|与|或|对|在|将|把|为|以|通过|结合|采用|参与|影响|调节|连接|提示)$", "", short).strip()
    return short or value[:max_chars].rstrip()


def _daily_digest_article_card_paragraphs(item: dict) -> list[str]:
    candidates = [
        _daily_digest_visual_topic(item),
        _daily_digest_visual_sentence(item.get("key_finding", ""), max_chars=46),
        _daily_digest_visual_sentence(item.get("conclusion_cn", ""), max_chars=46),
    ]
    scope = _daily_digest_visual_sentence(item.get("scope_note", ""), max_chars=36)
    if scope and re.search(r"(?:动物实验|小鼠|猕猴|体外|类器官|临床|样本)", scope):
        candidates.append(scope)
    cleaned = []
    seen = set()
    for text in candidates:
        text = _daily_digest_display_text(text, 64).strip(" ，,；;：:。")
        if not text or text in seen:
            continue
        if re.search(r"[？?]$", text):
            text = text.rstrip("？?")
        seen.add(text)
        cleaned.append(text)
    return cleaned[:3]

def _daily_digest_infer_evidence_path(source: dict) -> str:
    abstract = str(source.get("abstract", "") or "")
    title = str(source.get("title", "") or "")
    species = "小鼠" if re.search(r"\bmice\b|\bmouse\b", abstract, re.I) else "研究对象"
    methods = []
    if re.search(r"optogenetic|optogenetics", abstract, re.I):
        methods.append("光遗传")
    if re.search(r"vagus nerve stimulation|\bVNS\b", abstract, re.I):
        methods.append("迷走神经刺激")
    if re.search(r"dopamine", abstract, re.I):
        methods.append("多巴胺信号")
    pathway = ""
    if re.search(r"cNTS", abstract + title, re.I) and re.search(r"PAG|periaqueductal gray", abstract + title, re.I):
        pathway = "cNTS-PAG脑干通路"
    elif re.search(r"projection|pathway|circuit", abstract, re.I):
        pathway = "特定神经通路"
    method_text = "、".join(methods[:2]) if methods else "摘要所述实验"
    return f"{species}实验结合{method_text}，定位{pathway or '关键神经环路'}"


def _daily_digest_infer_scope_note(source: dict) -> str:
    abstract = str(source.get("abstract", "") or "")
    if re.search(r"\bmice\b|\bmouse\b", abstract, re.I):
        return "目前证据主要来自动物实验，不能直接等同于临床镇痛效果"
    return "结论应限于论文摘要所述样本、方法和实验条件"


