def _daily_digest_draw_symbol_cta(draw, box, spec: dict):
    x1, y1, x2, y2 = box
    accent = spec.get("accent") or "#E8799C"
    mode = spec.get("cta_mode")
    w = max(1, x2 - x1)
    h = max(1, y2 - y1)
    draw.rounded_rectangle(box, radius=max(12, int(h * 0.18)), fill="#FFFFFF", outline="#C8D9E7", width=max(1, int(h * 0.015)))
    centers = [x1 + int(w * 0.22), (x1 + x2) // 2, x2 - int(w * 0.22)]
    cy = y1 + int(h * 0.45)
    r = max(20, min(int(h * 0.30), int(w * 0.085)))
    stroke = max(3, int(r * 0.12))
    for idx, cx in enumerate(centers):
        draw.ellipse((cx - r, cy - r, cx + r, cy + r), fill="#FFFFFF", outline=accent, width=stroke)
        if mode == "wechat" and idx == 0:
            s = int(r * 0.40)
            draw.line((cx - s, cy, cx + s, cy), fill=accent, width=stroke + 1)
            draw.line((cx, cy - s, cx, cy + s), fill=accent, width=stroke + 1)
            draw.arc((cx - int(r * 0.54), cy - int(r * 0.54), cx + int(r * 0.54), cy + int(r * 0.54)), 215, 325, fill=accent, width=stroke)
        elif mode == "wechat" and idx == 2:
            draw.arc((cx - int(r * 0.52), cy - int(r * 0.30), cx + int(r * 0.46), cy + int(r * 0.46)), 20, 330, fill=accent, width=stroke + 1)
            draw.polygon([(cx + int(r * 0.44), cy - int(r * 0.40)), (cx + int(r * 0.66), cy + int(r * 0.10)), (cx + int(r * 0.15), cy + int(r * 0.05))], fill=accent)
        elif mode == "bilibili" and idx == 1:
            inner = int(r * 0.43)
            draw.ellipse((cx - inner, cy - inner, cx + inner, cy + inner), fill=accent)
            draw.rounded_rectangle((cx - int(r * 0.32), cy - int(r * 0.10), cx + int(r * 0.32), cy + int(r * 0.10)), radius=2, fill="#FFFFFF")
            draw.arc((cx - int(r * 0.24), cy - int(r * 0.32), cx + int(r * 0.24), cy + int(r * 0.32)), 70, 290, fill="#FFFFFF", width=max(2, int(stroke * 0.8)))
        elif mode == "bilibili" and idx == 2:
            import math
            pts = []
            for i in range(10):
                ang = -math.pi / 2 + i * math.pi / 5
                rr = int(r * (0.54 if i % 2 == 0 else 0.22))
                pts.append((cx + rr * math.cos(ang), cy + rr * math.sin(ang)))
            draw.polygon(pts, fill=accent)
        else:
            draw.ellipse((cx - int(r * 0.44), cy - int(r * 0.40), cx - int(r * 0.05), cy + int(r * 0.12)), fill=accent)
            draw.ellipse((cx + int(r * 0.05), cy - int(r * 0.40), cx + int(r * 0.44), cy + int(r * 0.12)), fill=accent)
            draw.polygon([(cx - int(r * 0.50), cy - int(r * 0.05)), (cx + int(r * 0.50), cy - int(r * 0.05)), (cx, cy + int(r * 0.56))], fill=accent)


def _daily_digest_issue_label(date_iso: str = "") -> str:
    raw = re.sub(r"\D+", "", str(date_iso or "").strip())
    if len(raw) >= 8:
        return raw[:8] + "期"
    try:
        return datetime.date.today().strftime("%Y%m%d") + "期"
    except Exception:
        return ""


def _daily_digest_issue_label_from_out_dir(out_dir: str = "", date_iso: str = "") -> str:
    name = os.path.basename(os.path.normpath(str(out_dir or "")))
    match = re.search(r"(\d{8})(?:[（(](\d{1,2})[）)])?", name)
    if match:
        date_part = match.group(1)
        issue_no = match.group(2)
        return f"{date_part}（{int(issue_no)}）期" if issue_no else f"{date_part}期"
    return _daily_digest_issue_label(date_iso)


def _daily_digest_issue_code(date_iso: str = "", issue_label: str = "") -> str:
    label = str(issue_label or "").strip()
    match = re.search(r"(\d{8})(?:[（(](\d{1,2})[）)])?", label)
    if match:
        return f"{match.group(1)}{int(match.group(2) or 1):02d}"
    raw = re.sub(r"\D+", "", str(date_iso or "").strip())
    if len(raw) >= 8:
        return raw[:8] + "01"
    return datetime.now().strftime("%Y%m%d") + "01"


def _daily_digest_clean_short_title(text: str) -> str:
    value = _daily_digest_display_text(text, 40)
    value = re.sub(r"[《》【】\[\]（）()“”\"'：:，,。.!！?？；;、\s]+", "", value)
    if len(value) > 16:
        value = value[:16]
    return value or "今日脑科学追新"


def _daily_digest_clean_cover_subtitle(text: str) -> str:
    value = _daily_digest_display_text(text, 80)
    value = re.sub(r"^(?:这项研究|该研究|研究者|研究)\s*(?:旨在|想回答的是|解析|显示|发现)?[，,:：\s]*", "", value)
    value = re.sub(r"^(?:结果|证据|实验)\s*(?:显示|提示|表明)[，,:：\s]*", "", value)
    value = re.split(r"[。；;.!?？]", value)[0].strip(" ，,；;：:")
    return value or "今日脑科学追新"


def _daily_digest_finalize_metadata(digest: dict, *, issue_label: str = "") -> dict:
    articles = digest.get("articles", []) or []
    issue_code = _daily_digest_issue_code(digest.get("date", ""), issue_label)
    digest["short_title"] = f"全澜脑科学追新助手 {issue_code}"
    digest["video_title"] = f"【全澜脑科学®追新助手】{issue_code}期"
    digest["closing_voiceover"] = "以上就是今天的全澜脑科学每日研究速递。关注全澜脑科学，下一期继续追踪具体问题和证据边界。"
    themes = []
    for item in articles[:5]:
        title = _daily_digest_strip_tail_punctuation(item.get("title_cn") or "")
        if not title:
            title = _daily_digest_strip_tail_punctuation((item.get("source", {}) or {}).get("title", ""))
        question = _daily_digest_strip_tail_punctuation(item.get("research_question") or "")
        if title:
            themes.append(title)
        elif question:
            themes.append(question)
    if themes:
        date_text = _daily_digest_display_text(digest.get("date", "") or _daily_digest_today_cn(), 32)
        first_question = ""
        for item in articles[:5]:
            first_question = _daily_digest_hook_question(item.get("research_question") or "", item.get("key_finding") or (item.get("source", {}) or {}).get("title", ""))
            if first_question:
                break
        first_question = first_question or "今天有哪些神经科学问题值得追踪？"
        digest["opening_voiceover"] = f"{first_question} 今天是{date_text}，这是全澜脑科学每日研究速递第{issue_code}期。"
        digest["catalog_voiceover"] = f"本期选取 {len(articles)} 篇论文，重点看方法、结果和证据边界。"
    else:
        date_text = _daily_digest_display_text(digest.get("date", "") or _daily_digest_today_cn(), 32)
        digest["opening_voiceover"] = f"今天有哪些神经科学问题值得追踪？今天是{date_text}，这是全澜脑科学每日研究速递第{issue_code}期。"
        digest["catalog_voiceover"] = "本期依次看论文的方法、结果和证据边界。"
    if themes:
        digest["video_description"] = _daily_digest_display_text("本期研究包括：" + "；".join(themes[:5]) + "。", 190)
    else:
        digest["video_description"] = "本期研究包括最新神经科学论文的科学问题、方法、结果、结论和证据边界。"
    return digest


