def _daily_digest_first_article_subtitle(digest: dict) -> str:
    articles = digest.get("articles", []) or []
    if not articles:
        return "用清晰机制读懂今天的脑科学"
    first = articles[0] or {}
    topic = _daily_digest_visual_topic(first)
    if topic:
        return _daily_digest_clean_cover_subtitle(topic)
    candidates = [
        first.get("key_finding", ""),
        first.get("research_question", ""),
        first.get("title_cn", ""),
        (first.get("source", {}) or {}).get("title", ""),
    ]
    text = ""
    for candidate in candidates:
        candidate = _daily_digest_display_text(candidate, 120)
        if candidate:
            text = candidate
            break
    text = re.sub(r"^(?:这项研究|该研究|研究者|研究)\s*(?:旨在|想回答的是|解析|显示|发现)?[，,:：\s]*", "", text)
    text = re.sub(r"^(?:结果|证据|实验)\s*(?:显示|提示|表明)[，,:：\s]*", "", text)
    replacements = [
        (r"尾侧孤束核投向导水管周围灰质的神经元.*", "脑干通路如何调节疼痛"),
        (r"迷走神经刺激.*疼痛.*", "迷走神经刺激如何影响疼痛"),
        (r"疼痛.*负性情感.*", "疼痛信号与负性情绪的脑干开关"),
        (r"类器官.*", "脑类器官图谱如何扩展细胞类型"),
        (r"AgRP|饥饿|禁食|能量", "大脑如何预判未来的饥饿"),
        (r"图式|记忆", "记忆理论中的抽象知识地图"),
        (r"AI|人工智能|大语言模型", "AI 如何重塑脑科学问题"),
    ]
    for pattern, replacement in replacements:
        if re.search(pattern, text, flags=re.I):
            return _daily_digest_clean_cover_subtitle(replacement)
    text = re.split(r"[。；;.!?？]", text)[0].strip()
    return _daily_digest_clean_cover_subtitle(text) or "用清晰机制读懂今天的脑科学"


def _daily_digest_integrated_cover_prompt(digest: dict) -> str:
    articles = digest.get("articles", []) or []
    parts = []
    for idx, item in enumerate(articles[:5], start=1):
        source = item.get("source", {}) or {}
        title = item.get("title_cn") or source.get("title", "")
        finding = item.get("key_finding") or item.get("research_question") or item.get("voiceover", "")
        parts.append(f"{idx}. {title}; {finding}")
    content = "\n".join(_daily_digest_display_text(x, 180) for x in parts if x)
    return f"""Create ONE organic, unified neuroscience content background image for a science media cover.

Non-negotiable picture rules:
- No text, no letters, no numbers, no logos, no labels, no captions, no watermark, no pseudo-writing.
- Do not make a collage, grid, poster, slide, article page, screenshot, card array, or separated panels.
- Do not draw any title, journal name, PMID, UI element, speech bubble, or annotation.

Image goal:
Synthesize the mechanisms from all listed papers into one coherent scientific illustration.
Make the image feel like a single Cell/Nature-style scientific editorial illustration, not five separate pictures.
Use biological forms: neural circuits, brain regions, cells, organoid-like tissue, synapses, molecular trafficking, signal dots, soft data-network arcs only when relevant.

Composition:
Landscape 16:9 cover background, premium biomedical editorial illustration.
Main scientific content should flow through the center and right side.
Leave clean negative space in the upper-left and lower areas for later overlaid Chinese title and logos.
Soft lighting, clear depth, refined color, no dark muddy background.

Scientific themes to merge:
{content}
"""


def _daily_digest_cover_background_status_path(path: str) -> str:
    return os.path.join(os.path.dirname(os.path.abspath(path)), "cover_background_status.json")


def _daily_digest_write_cover_background_status(path: str, digest: dict, *, status: str, image_engine: str = "", error: str = "") -> None:
    try:
        data = {
            "status": status,
            "target_path": path,
            "image_engine": image_engine,
            "prompt": _daily_digest_integrated_cover_prompt(digest),
            "updated_at": datetime.now().isoformat(timespec="seconds"),
        }
        if error:
            data["error"] = str(error)[:500]
        write_text_file(_daily_digest_cover_background_status_path(path), json.dumps(data, ensure_ascii=False, indent=2) + "\n")
    except Exception:
        pass


def _daily_digest_make_integrated_cover_background(path: str, digest: dict, *, image_engine: str = "", image_key: str = "", skip_image_api: bool = False, logger=print) -> str:
    last_error = ""
    if not skip_image_api and image_engine:
        prompt = _daily_digest_integrated_cover_prompt(digest)
        engines = []
        for engine in [
            image_engine,
            globals().get("IMAGE_ENGINE_GEMINI_31_FLASH", ""),
            globals().get("IMAGE_ENGINE_GPT_IMAGE2", ""),
        ]:
            if engine and engine not in engines:
                engines.append(engine)
        for attempt, engine in enumerate(engines, start=1):
            try:
                if logger:
                    logger(f"🎨 综合封面背景生图 {attempt}/{len(engines)}：{engine}。要求：融合本期文献内容，不出现任何文字或 logo。")
                ok = generate_image_by_engine(
                    engine,
                    prompt,
                    path,
                    logger,
                    openai_key=image_key,
                    chatshare_key="",
                    gemini_key=load_gemini_api_key(),
                )
                if ok and os.path.exists(path):
                    if logger:
                        logger(f"✅ 综合封面背景已生成：{path}")
                    return path
            except Exception as exc:
                last_error = str(exc)
                if logger:
                    logger(f"⚠️ 综合封面背景本次生图失败：engine={engine}，错误={str(exc)[:160]}")
    elif skip_image_api:
        last_error = "skip_image_api enabled"
    if logger:
        logger("⚠️ 综合封面背景未获得模型图片，已标记待补；不生成本地兜底背景。")
    try:
        if os.path.exists(path):
            os.remove(path)
    except Exception:
        pass
    _daily_digest_write_cover_background_status(path, digest, status="missing", image_engine=image_engine, error=last_error)
    return ""


def _daily_digest_make_integrated_local_content_background(path: str, digest: dict):
    import math
    from PIL import Image, ImageDraw, ImageFilter
    w, h = 1920, 1080
    img = Image.new("RGB", (w, h), "#EAF4FB")
    layer = Image.new("RGBA", (w, h), (0, 0, 0, 0))
    d = ImageDraw.Draw(layer)
    palette = [(32, 93, 154), (68, 156, 177), (105, 181, 143), (126, 109, 185), (230, 130, 106)]

    # Soft brain-like contour, drawn as shapes only.
    d.ellipse((1180, 115, 1740, 590), outline=(37, 82, 132, 92), width=9, fill=(255, 255, 255, 38))
    d.arc((1220, 150, 1510, 420), 210, 45, fill=(37, 82, 132, 105), width=7)
    d.arc((1390, 190, 1690, 500), 160, 350, fill=(37, 82, 132, 92), width=7)
    d.line((1465, 585, 1435, 720, 1500, 830), fill=(37, 82, 132, 82), width=10)

    articles = digest.get("articles", []) or []
    positions = [(260, 260), (620, 285), (980, 310), (1320, 760), (690, 760)]
    for idx, item in enumerate(articles[:5]):
        source = item.get("source", {}) or {}
        text = " ".join(str(x or "") for x in [
            item.get("title_cn"),
            item.get("research_question"),
            item.get("key_finding"),
            source.get("title"),
            source.get("abstract"),
        ]).lower()
        x, y = positions[idx % len(positions)]
        color = palette[idx % len(palette)]
        if re.search(r"内吞|endocyt|surface protein|表面蛋白|synap", text):
            d.arc((x - 130, y - 95, x + 130, y + 95), 190, 20, fill=(*color, 145), width=9)
            for j in range(6):
                cx = x - 92 + j * 38
                d.ellipse((cx - 9, y - 18, cx + 9, y + 18), fill=(*color, 120))
            for j in range(4):
                cx = x - 60 + j * 44
                d.ellipse((cx - 24, y + 55, cx + 24, y + 103), outline=(*color, 115), width=5, fill=(*color, 24))
        elif re.search(r"类器官|organoid|midbrain|hindbrain|cerebell", text):
            for j in range(24):
                cx = x + int(((j * 37) % 150) - 75)
                cy = y + int(((j * 53) % 140) - 70)
                r = 10 + (j % 4) * 4
                d.ellipse((cx - r, cy - r, cx + r, cy + r), fill=(*color, 90), outline=(*color, 130), width=2)
        elif re.search(r"迷走|vagal|pain|疼痛|brainstem|脑干", text):
            d.arc((x - 150, y - 120, x + 150, y + 120), 215, 35, fill=(*color, 150), width=8)
            d.line((x - 80, y + 10, x + 35, y + 48, x + 125, y - 40), fill=(*color, 135), width=7)
            for cx, cy in [(x - 82, y + 10), (x + 35, y + 48), (x + 125, y - 40)]:
                d.ellipse((cx - 18, cy - 18, cx + 18, cy + 18), fill=(*color, 150))
        elif re.search(r"agrp|hunger|饥饿|hypothalam|下丘脑|energy", text):
            d.ellipse((x - 90, y - 70, x + 90, y + 70), outline=(*color, 150), width=8, fill=(*color, 26))
            for j in range(18):
                angle = j / 18 * 6.283
                cx = x + int(145 * math.cos(angle))
                cy = y + int(95 * math.sin(angle))
                d.line((x, y, cx, cy), fill=(*color, 45), width=3)
                d.ellipse((cx - 8, cy - 8, cx + 8, cy + 8), fill=(*color, 115))
        elif re.search(r"ai|schema|memory|model|人工智能|图式|记忆", text):
            pts = []
            for j in range(12):
                cx = x + int(((j * 71) % 260) - 130)
                cy = y + int(((j * 43) % 180) - 90)
                pts.append((cx, cy))
                d.ellipse((cx - 10, cy - 10, cx + 10, cy + 10), fill=(*color, 125))
            for a, b in zip(pts, pts[1:]):
                d.line((a, b), fill=(*color, 75), width=4)
        else:
            d.line((x - 150, y, x - 40, y - 35, x + 30, y + 20, x + 150, y - 20), fill=(*color, 130), width=7)
            for cx, cy in [(x - 150, y), (x - 40, y - 35), (x + 30, y + 20), (x + 150, y - 20)]:
                d.ellipse((cx - 20, cy - 20, cx + 20, cy + 20), fill=(*color, 125))

    for i in range(34):
        x0 = int(w * (0.08 + ((i * 29) % 82) / 100))
        y0 = int(h * (0.12 + ((i * 47) % 76) / 100))
        r = 5 + (i % 5) * 3
        color = palette[i % len(palette)]
        d.ellipse((x0 - r, y0 - r, x0 + r, y0 + r), fill=(*color, 62))
    layer = layer.filter(ImageFilter.GaussianBlur(2.2))
    veil = Image.new("RGBA", (w, h), (255, 255, 255, 72))
    result = Image.alpha_composite(img.convert("RGBA"), layer)
    result = Image.alpha_composite(result, veil)
    result.convert("RGB").save(path, "PNG")


def _daily_digest_make_integrated_visual_blend_background(path: str, digest: dict):
    visual_dir = os.path.dirname(os.path.abspath(path))
    sources: list[str] = []
    try:
        for name in sorted(os.listdir(visual_dir)):
            if not name.lower().endswith((".png", ".jpg", ".jpeg", ".webp")):
                continue
            if "integrated_cover_background" in name:
                continue
            if re.search(r"_PMID_.*_visual", name) or name.startswith(("01_", "02_", "03_", "04_", "05_")):
                sources.append(os.path.join(visual_dir, name))
    except Exception:
        sources = []
    if sources:
        _daily_digest_make_blended_background_from_images(path, sources[:5])
    else:
        _daily_digest_make_integrated_placeholder_background(path, digest)


def _daily_digest_make_blended_background_from_images(path: str, image_paths: list[str]):
    from PIL import Image, ImageDraw, ImageFilter, ImageOps
    w, h = 1920, 1080
    canvas = Image.new("RGBA", (w, h), "#EAF4FB")
    positions = [
        (int(w * 0.42), int(h * -0.04), int(w * 0.54), 0.44),
        (int(w * 0.04), int(h * 0.10), int(w * 0.48), 0.34),
        (int(w * 0.56), int(h * 0.38), int(w * 0.42), 0.32),
        (int(w * 0.22), int(h * 0.48), int(w * 0.40), 0.26),
        (int(w * 0.74), int(h * 0.10), int(w * 0.34), 0.24),
    ]
    for idx, src in enumerate(image_paths[:5]):
        try:
            with Image.open(src) as opened:
                img = opened.convert("RGB")
        except Exception:
            continue
        x, y, size, alpha = positions[idx % len(positions)]
        tile = ImageOps.fit(img, (size, size), method=Image.Resampling.LANCZOS).convert("RGBA")
        tile = tile.filter(ImageFilter.GaussianBlur(18 if idx < 2 else 24))
        mask = Image.new("L", (size, size), 0)
        d = ImageDraw.Draw(mask)
        d.ellipse((0, 0, size, size), fill=int(255 * alpha))
        mask = mask.filter(ImageFilter.GaussianBlur(int(size * 0.08)))
        tile.putalpha(mask)
        canvas.alpha_composite(tile, (x, y))
    veil = Image.new("RGBA", (w, h), (234, 244, 251, 150))
    canvas = Image.alpha_composite(canvas, veil)
    canvas = canvas.filter(ImageFilter.GaussianBlur(1.2))
    canvas.convert("RGB").save(path, "PNG")


def _daily_digest_make_integrated_placeholder_background(path: str, digest: dict):
    from PIL import Image, ImageDraw, ImageFilter
    w, h = 1920, 1080
    img = Image.new("RGB", (w, h), "#EAF4FB")
    layer = Image.new("RGBA", (w, h), (0, 0, 0, 0))
    d = ImageDraw.Draw(layer)
    palette = [(20, 74, 122), (51, 132, 173), (99, 174, 154), (118, 101, 178), (235, 124, 92)]
    for i in range(16):
        x0 = int(w * (0.06 + (i % 4) * 0.24))
        y0 = int(h * (0.18 + (i // 4) * 0.18))
        x1 = int(x0 + w * (0.18 + (i % 3) * 0.03))
        y1 = int(y0 + h * (0.10 + (i % 2) * 0.04))
        color = palette[i % len(palette)]
        d.ellipse((x0, y0, x1, y1), outline=(*color, 72), width=5, fill=(*color, 18))
    points = []
    for i in range(28):
        x = int(w * (0.08 + ((i * 37) % 84) / 100))
        y = int(h * (0.16 + ((i * 53) % 70) / 100))
        points.append((x, y))
        r = 8 + (i % 5) * 3
        color = palette[i % len(palette)]
        d.ellipse((x - r, y - r, x + r, y + r), fill=(*color, 145))
    for i in range(len(points) - 1):
        color = palette[i % len(palette)]
        d.line((points[i], points[i + 1]), fill=(*color, 90), width=4)
    d.arc((int(w * 0.18), int(h * 0.12), int(w * 0.82), int(h * 0.88)), 205, 25, fill=(16, 51, 91, 80), width=8)
    layer = layer.filter(ImageFilter.GaussianBlur(1.4))
    Image.alpha_composite(img.convert("RGBA"), layer).convert("RGB").save(path, "PNG")


def _daily_digest_draw_integrated_cover_platform(path: str, digest: dict, *, size: tuple[int, int], issue_label: str = "", background_path: str = ""):
    from PIL import Image, ImageDraw, ImageFilter, ImageOps
    w, h = size
    if background_path and os.path.exists(background_path):
        with Image.open(background_path) as opened:
            bg = opened.convert("RGB")
        resample = getattr(getattr(Image, "Resampling", Image), "LANCZOS", Image.LANCZOS)
        img = ImageOps.fit(bg, (w, h), method=resample, centering=(0.5, 0.5))
    else:
        img, _ = _daily_digest_platform_base(size)
    img = img.convert("RGBA")
    overlay = Image.new("RGBA", (w, h), (0, 0, 0, 0))
    od = ImageDraw.Draw(overlay)
    od.rectangle((0, 0, w, h), fill=(244, 248, 251, 134))
    od.rectangle((0, 0, int(w * 0.42), h), fill=(246, 250, 252, 176))
    od.rectangle((0, int(h * 0.80), w, h), fill=(237, 244, 249, 156))
    od.rectangle((0, 0, max(14, int(w * 0.018)), h), fill=(28, 75, 110, 226))
    od.rectangle((max(14, int(w * 0.018)), 0, max(18, int(w * 0.023)), h), fill=(102, 165, 184, 210))
    img = Image.alpha_composite(img, overlay).convert("RGB")
    d = ImageDraw.Draw(img)
    # A-cover backgrounds stay free of text-like marks; this layer supplies
    # the deterministic magazine title system for every platform ratio.
    issue = _daily_digest_display_text(_daily_digest_issue_code(digest.get("date", ""), issue_label) + "期", 24)
    portrait = h > w
    text_panel = _daily_digest_box(size, (0.095, 0.145, 0.905, 0.735) if portrait else (0.075, 0.160, 0.540, 0.780))
    panel_fill = "#FFFFFF" if portrait else "#FBFDFF"
    _daily_digest_draw_soft_panel(
        d,
        text_panel,
        radius=max(18, int(min(w, h) * 0.022)),
        fill=panel_fill,
        outline="#D5E0E9",
        width=2,
    )
    accent = "#2F89A8"
    d.rectangle((int(w * 0.070), int(h * 0.075), int(w * 0.150), int(h * 0.082)), fill="#D47B64")
    d.rectangle((int(w * 0.150), int(h * 0.075), int(w * 0.255), int(h * 0.082)), fill=accent)
    if not portrait:
        _daily_digest_paste_logo(img, lang="zh", x=text_panel[0] + int(w * 0.020), y=text_panel[1] + int(h * 0.030), target_h=max(32, int(h * 0.052)), max_w=int((text_panel[2] - text_panel[0]) * 0.62), opacity=242)
    else:
        _daily_digest_paste_logo(img, lang="zh", center_x=w // 2, y=text_panel[1] + int(h * 0.035), target_h=max(42, int(h * 0.050)), max_w=int(w * 0.62), opacity=242)

    label_y = text_panel[1] + int((text_panel[3] - text_panel[1]) * (0.22 if portrait else 0.20))
    _daily_digest_draw_meta_pill(
        d,
        (text_panel[0] + int(w * 0.035), label_y, text_panel[0] + int(w * (0.35 if portrait else 0.21)), label_y + max(46, int(h * 0.052))),
        issue or "Daily Digest",
        accent="#D47B64",
    )
    _daily_digest_draw_magazine_rule(d, text_panel[0] + int(w * 0.035), label_y + max(72, int(h * 0.075)), text_panel[2] - int(w * 0.035), accent=accent)
    title_top = label_y + max(92, int(h * 0.100))
    title_bottom = title_top + max(82, int(h * (0.165 if portrait else 0.175)))
    _daily_digest_draw_fit_box(
        d,
        "每日研究速递",
        (text_panel[0] + int(w * 0.035), title_top, text_panel[2] - int(w * 0.035), title_bottom),
        min_size=max(46, int(h * (0.055 if portrait else 0.065))),
        max_size=max(62, int(h * (0.086 if portrait else 0.100))),
        weight=940,
        fill="#102A50",
        max_lines=1,
        align="left" if not portrait else "center",
        line_gap_ratio=0.14,
    )
    subtitle = _daily_digest_first_article_subtitle(digest)
    sub_top = title_bottom + max(18, int(h * 0.030))
    sub_bottom = text_panel[3] - max(44, int(h * 0.070))
    _daily_digest_draw_fit_box(
        d,
        subtitle,
        (text_panel[0] + int(w * 0.040), sub_top, text_panel[2] - int(w * 0.040), sub_bottom),
        min_size=max(26, int(h * (0.030 if portrait else 0.034))),
        max_size=max(38, int(h * (0.048 if portrait else 0.054))),
        weight=850,
        fill="#24496F",
        max_lines=3,
        align="left" if not portrait else "center",
        line_gap_ratio=0.20,
    )
    footer_y = int(h * 0.865)
    _daily_digest_draw_magazine_rule(d, int(w * 0.075), footer_y, int(w * 0.925), accent=accent)
    footer = "QuanLan BrainScience | Neuroscience Frontiers"
    _daily_digest_draw_fit_box(
        d,
        footer,
        (int(w * 0.080), footer_y + max(10, int(h * 0.018)), int(w * 0.920), footer_y + max(54, int(h * 0.070))),
        min_size=max(18, int(h * 0.018)),
        max_size=max(24, int(h * 0.028)),
        weight=650,
        fill="#5B7188",
        max_lines=1,
        align="center",
    )
    img.save(path, "PNG")


def _daily_digest_draw_card_array_platform(path: str, card_paths: list[str], *, size: tuple[int, int], title: str, issue_label: str = "", digest: dict | None = None, background_path: str = ""):
    if isinstance(digest, dict):
        _daily_digest_draw_integrated_cover_platform(path, digest, size=size, issue_label=issue_label, background_path=background_path)
        return
    from PIL import Image, ImageDraw
    img, d = _daily_digest_platform_base(size)
    w, h = size
    _daily_digest_center_text(d, title, int(h * 0.08), _daily_digest_font(max(28, int(h * 0.052)), weight=900), "#102A50", w)
    issue = _daily_digest_display_text(issue_label, 24)
    if issue:
        _daily_digest_center_text(d, issue, int(h * 0.15), _daily_digest_font(max(18, int(h * 0.026)), weight=800), "#607893", w)
    usable = (int(w * 0.07), int(h * 0.22), int(w * 0.93), int(h * 0.91))
    cols = 3 if w >= h else 2
    rows = 2 if w >= h else 3
    gap = max(12, int(min(w, h) * 0.025))
    cell_w = (usable[2] - usable[0] - gap * (cols - 1)) // cols
    cell_h = (usable[3] - usable[1] - gap * (rows - 1)) // rows
    for i, p in enumerate([x for x in card_paths if x and os.path.exists(x)][:cols * rows]):
        r = i // cols
        c = i % cols
        x1 = usable[0] + c * (cell_w + gap)
        y1 = usable[1] + r * (cell_h + gap)
        d.rounded_rectangle((x1, y1, x1 + cell_w, y1 + cell_h), radius=max(8, int(gap * 0.7)), fill="#FFFFFF", outline="#C8D9E7", width=2)
        try:
            with Image.open(p) as opened:
                card = opened.convert("RGB")
            _daily_digest_paste_contain(img, card, (x1 + gap, y1 + gap, x1 + cell_w - gap, y1 + cell_h - gap), bg="#FFFFFF")
        except Exception:
            pass
    img.save(path, "PNG")


def _daily_digest_export_platform_ac_cards(cards_dir: str, digest: dict, *, issue_label: str = "", cover_background_path: str = "", logger=print):
    platform_dir = os.path.join(os.path.dirname(cards_dir), "platform_cards")
    os.makedirs(platform_dir, exist_ok=True)
    has_cover_background = bool(cover_background_path and os.path.exists(cover_background_path))
    card_paths = [
        os.path.join(cards_dir, name)
        for name in sorted(os.listdir(cards_dir))
        if name.lower().endswith(".png")
    ]
    specs = [
        ("A_微信视频号封面_3x4.png", "home", "wechat", (1080, 1440)),
        ("C_微信视频号品牌页_3x4.png", "closing", "wechat", (1080, 1440)),
        ("卡片阵列_微信视频号_9x16.png", "array", "wechat", (1080, 1920)),
        ("A_B站封面_4x3.png", "home", "bilibili", (1440, 1080)),
        ("C_B站品牌页_4x3.png", "closing", "bilibili", (1440, 1080)),
        ("卡片阵列_B站_16x9.png", "array", "bilibili", (1920, 1080)),
    ]
    for filename, kind, platform, size in specs:
        out = os.path.join(platform_dir, filename)
        if kind == "home":
            if not has_cover_background:
                if logger:
                    logger(f"⚠️ 跳过平台封面：缺少真实综合背景，待补后再生成 {filename}")
                continue
            _daily_digest_draw_integrated_cover_platform(out, digest, size=size, issue_label=issue_label, background_path=cover_background_path)
        elif kind == "closing":
            _daily_digest_draw_closing_platform(out, digest, platform=platform, size=size, issue_label=issue_label)
        else:
            if not has_cover_background:
                if logger:
                    logger(f"⚠️ 跳过平台阵列图：缺少真实综合背景，待补后再生成 {filename}")
                continue
            _daily_digest_draw_card_array_platform(out, card_paths, size=size, title="每日研究速递", issue_label=issue_label, digest=digest, background_path=cover_background_path)
    if logger:
        logger(f"✅ 每日研究速递平台封面与品牌页已生成：{platform_dir}")
    return platform_dir


def _daily_digest_write_voiceover(path: str, digest: dict):
    lines = [digest.get("opening_voiceover", "").strip(), digest.get("catalog_voiceover", "").strip()]
    for idx, item in enumerate(digest.get("articles", []), start=1):
        lines.append(f"{idx}. " + str(item.get("voiceover", "")).strip())
    lines.append(digest.get("closing_voiceover", "").strip())
    write_text_file(path, "\n\n".join(x for x in lines if x).strip() + "\n")


def _daily_digest_write_video_meta(path: str, digest: dict):
    payload = {
        "short_title": digest.get("short_title", ""),
        "video_title": digest.get("video_title", ""),
        "video_description": digest.get("video_description", ""),
    }
    write_text_file(
        path,
        f"标题：{payload['video_title']}\n短标题：{payload['short_title']}\n\n简介：\n{payload['video_description']}\n",
    )
    write_text_file(os.path.splitext(path)[0] + ".json", json.dumps(payload, ensure_ascii=False, indent=2) + "\n")


def _daily_digest_write_lrc(path: str, digest: dict):
    cues = [digest.get("opening_voiceover", ""), digest.get("catalog_voiceover", "")]
    cues.extend(str(x.get("voiceover", "")) for x in digest.get("articles", []))
    cues.append(digest.get("closing_voiceover", ""))
    seconds = 0
    lines = []
    for text in cues:
        mm, ss = divmod(seconds, 60)
        lines.append(f"[{mm:02d}:{ss:02d}.00]{_daily_digest_safe_text(text, 220)}")
        seconds += max(6, min(18, int(len(str(text)) / 6) + 4))
    write_text_file(path, "\n".join(lines).rstrip() + "\n")


def _daily_digest_write_text_assets(
    out_dir: str,
    digest: dict,
    articles: list[dict],
    *,
    image_prompts: list[str] | None = None,
    logger=print,
) -> None:
    os.makedirs(out_dir, exist_ok=True)
    digest_articles = [x for x in digest.get("articles", []) if isinstance(x, dict)]
    source_articles = articles or [x.get("source", {}) for x in digest_articles if isinstance(x.get("source", {}), dict)]
    prompt_rows: list[dict] = []
    prompt_text: list[str] = []
    for idx, item in enumerate(digest_articles, start=1):
        source = item.get("source", {}) or {}
        prompt = str(item.get("image_prompt", "")).strip()
        row = {
            "index": idx,
            "pmid": str(source.get("pmid", "") or item.get("pmid", "")).strip(),
            "journal": source.get("journal", ""),
            "title": source.get("title", "") or item.get("title_cn", ""),
            "image_prompt": prompt,
            "visual_status": item.get("_visual_status", ""),
            "visual_path": item.get("_visual_path", ""),
        }
        prompt_rows.append(row)
        prompt_text.append(f"## {idx:02d} PMID {row['pmid']}\n{prompt}\n")

    write_text_file(
        os.path.join(out_dir, "00_文献信息.json"),
        json.dumps([_daily_digest_public_article(x) for x in source_articles if isinstance(x, dict)], ensure_ascii=False, indent=2) + "\n",
    )
    write_text_file(os.path.join(out_dir, "01_栏目素材.json"), json.dumps(digest, ensure_ascii=False, indent=2) + "\n")
    _daily_digest_write_voiceover(os.path.join(out_dir, "02_口播台词.txt"), digest)
    write_text_file(
        os.path.join(out_dir, "03_图片提示词.txt"),
        "\n".join(image_prompts or prompt_text).strip() + "\n",
    )
    write_text_file(os.path.join(out_dir, "03_图片提示词.json"), json.dumps(prompt_rows, ensure_ascii=False, indent=2) + "\n")
    _daily_digest_write_video_meta(os.path.join(out_dir, "04_视频简介.txt"), digest)
    _daily_digest_write_lrc(os.path.join(out_dir, "05_口播字幕.lrc"), digest)
    if logger:
        logger("✅ 文案文件已写入：00_文献信息、01_栏目素材、02_口播台词、03_图片提示词、04_视频简介、05_口播字幕。")


def _daily_digest_package_and_email(out_dir: str, *, enabled: bool = False, recipient: str = "", logger=print) -> str:
    if not enabled:
        return ""
    parser = globals().get("parse_email_recipients")
    package = globals().get("package_and_optionally_email_chapter")
    if not callable(parser) or not callable(package):
        if logger:
            logger("⚠️ 每日研究速递邮件未发送：当前运行环境缺少邮件发送模块。")
        return ""
    if not parser(recipient):
        if logger:
            logger("⚠️ 已开启每日研究速递邮件发送，但收件邮箱为空或格式无效。")
        return ""
    return package(
        out_dir,
        enabled=True,
        recipient=recipient,
        chapter_title="每日研究速递",
        book_name="全澜脑科学",
        logger=logger,
    )


def run_daily_research_digest(
    *,
    out_dir: str = "",
    days: int = 14,
    max_articles: int = 5,
    journals: str = "",
    article_list_path: str = "",
    continue_until_exhausted: bool = False,
    resume_existing: bool = False,
    text_engine: str = "GPT-5.5",
    polish_engine: str = "DeepSeek Chat（官方润色）",
    image_engine: str = IMAGE_ENGINE_GPT_IMAGE2,
    skip_image_api: bool = False,
    deepseek_key: str = "",
    openai_key: str = "",
    image_key: str = "",
    chatshare_key: str = "",
    gemini_key: str = "",
    grok_key: str = "",
    doubao_key: str = "",
    doubao_endpoint: str = "",
    email_after_completion: bool = False,
    email_recipient: str = "",
    logger=print,
) -> str:
    if continue_until_exhausted:
        if not article_list_path:
            raise RuntimeError("续做已有文献清单需要指定 --daily-article-list。")
        articles, resolved_list_path = _daily_digest_load_article_list(article_list_path)
        base_dir = _daily_digest_continue_base_dir(out_dir)
        generated_dirs: list[str] = []
        if logger:
            logger(f"已有文献清单续做启动：{resolved_list_path}")
            logger(f"续做输出根目录：{base_dir}")
        remaining_total = len([x for x in articles if str(x.get("pmid", "")).strip()]) - len(_daily_digest_list_used_pmids(resolved_list_path))
        indexed_issues = remaining_total > max_articles
        while True:
            next_batch = _daily_digest_select_from_existing_list(
                articles,
                max_articles=max_articles,
                article_list_path=resolved_list_path,
                logger=logger,
            )
            if not next_batch:
                if logger:
                    logger(f"已有文献清单已用完：共生成 {len(generated_dirs)} 期。")
                return generated_dirs[-1] if generated_dirs else base_dir
            issue_dir = _daily_digest_next_issue_dir(base_dir, indexed=indexed_issues)
            if logger:
                logger(f"续做清单：开始生成第 {len(generated_dirs) + 1} 期，输出目录：{issue_dir}")
            generated = run_daily_research_digest(
                out_dir=issue_dir,
                days=days,
                max_articles=max_articles,
                journals=journals,
                article_list_path=resolved_list_path,
                continue_until_exhausted=False,
                resume_existing=False,
                text_engine=text_engine,
                polish_engine=polish_engine,
                image_engine=image_engine,
                skip_image_api=skip_image_api,
                deepseek_key=deepseek_key,
                openai_key=openai_key,
                image_key=image_key,
                chatshare_key="",
                gemini_key=gemini_key,
                grok_key=grok_key,
                doubao_key=doubao_key,
                doubao_endpoint=doubao_endpoint,
                email_after_completion=email_after_completion,
                email_recipient=email_recipient,
                logger=logger,
            )
            generated_dirs.append(generated)

    _daily_digest_prepare_relay_env(logger=logger)
    date_iso = _daily_digest_iso_date()
    date_cn = _daily_digest_today_cn()
    out_dir = os.path.abspath(out_dir or os.path.join(BASE_SAVE_FOLDER, "每日研究速递", date_iso))
    cards_dir = os.path.join(out_dir, "cards")
    visual_dir = os.path.join(out_dir, "visual_summaries")
    os.makedirs(cards_dir, exist_ok=True)
    os.makedirs(visual_dir, exist_ok=True)
    issue_label = _daily_digest_issue_label_from_out_dir(out_dir, date_iso)
    if resume_existing and not article_list_path:
        discovered_article_list = _daily_digest_find_article_list_near_issue(out_dir)
        if discovered_article_list:
            article_list_path = discovered_article_list
            if logger:
                logger(f"断档续作：已在档期上级目录自动找到文献清单：{article_list_path}")
    if logger:
        logger(f"📁 每日研究速递输出目录：{out_dir}")
        if resume_existing:
            logger("📄 断档续作：将优先复用档期内已有素材；缺失文献信息时从文献清单恢复。")
        elif article_list_path:
            logger(f"📄 续做已有文献清单：目标 {max_articles} 篇/期。")
        else:
            logger(f"🔎 文献检索设置：近 {days} 天，目标 {max_articles} 篇，按期刊轮转并避开近期已用 PMID。")

    daily_journals = _daily_digest_parse_journals(journals)
    resolved_list_path = ""
    if resume_existing:
        article_list, digest, resolved_list_path, loaded_digest_path = _daily_digest_load_existing_issue(out_dir)
        if not article_list and article_list_path:
            article_list, recovered_list_path = _daily_digest_recover_articles_from_visuals(
                out_dir,
                article_list_path,
                max_articles=max_articles,
                logger=logger,
            )
            if recovered_list_path:
                resolved_list_path = recovered_list_path
        if logger:
            logger(f"续作档期文献清单：{resolved_list_path or '未在档期内找到，已尝试从当前文献清单恢复'}")
            logger(f"续作档期素材文件：{loaded_digest_path if os.path.exists(loaded_digest_path) else '未找到现有 01_栏目素材.json'}")
        if not article_list:
            visual_pmids = _daily_digest_pmids_from_existing_visuals(out_dir)
            raise RuntimeError(
                "断档续作没有恢复到可用文献。"
                f" 已从图片中识别 PMID {len(visual_pmids)} 个：{', '.join(visual_pmids[:8]) or '无'}。"
                " 请确认“文献清单”是生成这些图片时使用的清单，或把对应的 文献清单_*.json 放在档期上级目录。"
            )
        if os.path.exists(loaded_digest_path):
            try:
                digest = _daily_digest_prepare_resumed_digest(digest, article_list, date_cn, issue_label=issue_label, logger=logger)
            except Exception as exc:
                if logger:
                    logger(f"读取已有栏目素材失败，改为重新生成：{type(exc).__name__}: {exc}")
                digest = build_daily_research_digest(
                    article_list,
                    date_text=date_cn,
                    text_engine=text_engine,
                    polish_engine=polish_engine,
                    deepseek_key=deepseek_key,
                    openai_key=openai_key,
                    chatshare_key="",
                    gemini_key=gemini_key,
                    grok_key=grok_key,
                    logger=logger,
                )
                digest = _daily_digest_finalize_metadata(digest, issue_label=issue_label)
        else:
            if logger:
                logger("未找到可复用的栏目素材，改为基于现有文献清单重新生成。")
            digest = build_daily_research_digest(
                article_list,
                date_text=date_cn,
                text_engine=text_engine,
                polish_engine=polish_engine,
                deepseek_key=deepseek_key,
                openai_key=openai_key,
                chatshare_key="",
                gemini_key=gemini_key,
                grok_key=grok_key,
                logger=logger,
            )
            digest = _daily_digest_finalize_metadata(digest, issue_label=issue_label)
    elif article_list_path:
        all_articles, resolved_list_path = _daily_digest_load_article_list(article_list_path)
        article_list = _daily_digest_select_from_existing_list(
            all_articles,
            max_articles=max_articles,
            article_list_path=resolved_list_path,
            logger=logger,
        )
    else:
        article_list = fetch_daily_neuroscience_articles(
            days=days,
            max_articles=max_articles,
            journals=daily_journals,
            logger=logger,
        )
    if not article_list:
        if resume_existing:
            raise RuntimeError(
                "续作档期没有读到可用文献。请确认 --daily-out-dir 指向某一期档期文件夹，"
                "例如“...\\科研速递\\20260605（1）”，不要指向“科研速递”总目录。"
                "档期文件夹内通常应包含 00_文献信息.json、00_候选文献清单.json 或 01_栏目素材.json。"
            )
        if article_list_path:
            raise RuntimeError("已有文献清单中没有剩余可用文献。")
        raise RuntimeError("没有检索到可用的最新神经科学论文。可尝试增大 --daily-days 或调整 --daily-journals。")
    if logger:
        logger(f"文献清单读取完成：{len(article_list)} 篇" if (article_list_path or resume_existing) else f"文献检索完成：{len(article_list)} 篇")
        for idx, article in enumerate(article_list, start=1):
            logger(f"   {idx}. {article.get('journal', 'Unknown')} | PMID {article.get('pmid', '')} | {str(article.get('title', ''))[:80]}")
        if not resume_existing:
            logger(f"正在生成栏目素材：翻译/结构化={text_engine}，中文润色={polish_engine}")
    if not resume_existing:
        _daily_digest_mark_articles_used(article_list, issue_dir=out_dir, journals=daily_journals)
        digest = build_daily_research_digest(
            article_list,
            date_text=date_cn,
            text_engine=text_engine,
            polish_engine=polish_engine,
            deepseek_key=deepseek_key,
            openai_key=openai_key,
            chatshare_key="",
            gemini_key=gemini_key,
            grok_key=grok_key,
            logger=logger,
        )
        digest = _daily_digest_finalize_metadata(digest, issue_label=issue_label)
    _daily_digest_write_text_assets(out_dir, digest, article_list, logger=logger)
    image_prompts = []
    total_articles = len(digest.get("articles", []))
    consecutive_image_api_failures = 0
    for idx, item in enumerate(digest.get("articles", []), start=1):
        source = item.get("source", {}) or {}
        prompt = _daily_digest_force_square_image_prompt(
            source,
            item.get("image_prompt") or _daily_digest_image_prompt(source, item.get("key_finding", "")),
            item.get("key_finding", ""),
        )
        item["image_prompt"] = prompt
        image_prompts.append(f"## {idx:02d} PMID {source.get('pmid','')}\n{prompt}\n")
        visual_path = os.path.join(visual_dir, f"{idx:02d}_PMID_{source.get('pmid','unknown')}_visual.png")
        existing_status = str(item.get("_visual_status", "")).strip().lower()
        existing_visual_ready = bool(resume_existing and _daily_digest_prepare_existing_visual_summary(visual_path, logger=logger))
        if existing_visual_ready and (skip_image_api or existing_status != "placeholder"):
            item["_visual_status"] = "existing" if existing_status != "api" else existing_status
            item["_visual_path"] = visual_path
            if logger:
                logger(f"图片摘要 {idx}/{total_articles} 已在档期目录中识别到，跳过生图：PMID {source.get('pmid','')}，{os.path.basename(visual_path)}")
            continue
        if skip_image_api:
            if logger:
                logger(f"图片摘要 {idx}/{total_articles}：已选择跳过 API，生成本地占位图")
            _daily_digest_make_placeholder_visual(visual_path, source)
            item["_visual_status"] = "placeholder"
        else:
            if consecutive_image_api_failures >= 2:
                if logger:
                    logger(
                        f"图片摘要 {idx}/{total_articles}：前面已连续 {consecutive_image_api_failures} 次生图失败，"
                        f"本轮不再继续请求 API，直接标记待补图：PMID {source.get('pmid','')}"
                    )
                item["_visual_status"] = "missing"
                item["_visual_path"] = ""
                continue
            effective_image_key = _daily_digest_load_image_api_key() or image_key or openai_key
            if logger:
                logger(f"图片摘要 {idx}/{total_articles} 开始：PMID {source.get('pmid','')}，engine={image_engine}，保存到 {visual_path}")
                logger("生图请求已进入等待，这一步通常需要 80-150 秒；完成或失败后会继续打印下一条日志。")
            heartbeat = _daily_digest_progress_heartbeat(f"图片摘要 {idx}/{total_articles} 生图", logger, interval=15)
            try:
                ok = generate_image_by_engine(
                    image_engine,
                    prompt,
                    visual_path,
                    logger,
                    openai_key=effective_image_key,
                    chatshare_key="",
                    gemini_key=gemini_key or load_gemini_api_key(),
                )
            finally:
                heartbeat.set()
            if not ok:
                consecutive_image_api_failures += 1
                if logger:
                    logger(f"图片摘要 {idx}/{total_articles} API 未生成真实图，已标记为待补图，不生成占位图：PMID {source.get('pmid','')}")
                item["_visual_status"] = "missing"
                visual_path = ""
            else:
                consecutive_image_api_failures = 0
                _daily_digest_normalize_visual_summary(visual_path, logger=logger)
                item["_visual_status"] = "api"
                if logger:
                    logger(f"图片摘要 {idx}/{total_articles} 完成：PMID {source.get('pmid','')}，规格 {DAILY_DIGEST_VISUAL_W}×{DAILY_DIGEST_VISUAL_H}")
        item["_visual_path"] = visual_path
    _daily_digest_write_text_assets(out_dir, digest, article_list, image_prompts=image_prompts, logger=logger)
    cover_background_path = os.path.join(visual_dir, "00_daily_digest_integrated_cover_background.png")
    cover_background_path = _daily_digest_make_integrated_cover_background(
        cover_background_path,
        digest,
        image_engine=image_engine,
        image_key=_daily_digest_load_image_api_key() or image_key or openai_key,
        skip_image_api=bool(skip_image_api),
        logger=logger,
    )

    if logger:
        logger("🧩 正在绘制卡片：首页")
    _daily_digest_draw_home(os.path.join(cards_dir, "01_首页_每日研究速递.png"), digest, date_cn, issue_label=issue_label)
    if logger:
        logger("🧩 正在绘制卡片：目录页")
    _daily_digest_draw_catalog(os.path.join(cards_dir, "02_目录_口播.png"), digest)
    total = len(digest.get("articles", []))
    for idx, item in enumerate(digest.get("articles", []), start=1):
        source = item.get("source", {}) or {}
        pmid = source.get("pmid", f"{idx:02d}")
        if logger:
            logger(f"🧩 正在绘制卡片：文献 {idx}/{total}，PMID {pmid}")
        _daily_digest_draw_article_card(
            os.path.join(cards_dir, f"{idx + 2:02d}_文献_{pmid}.png"),
            item,
            idx,
            total,
            visual_path=item.get("_visual_path", ""),
        )
    if logger:
        logger("🧩 正在绘制品牌页：微信短视频版")
    _daily_digest_draw_closing(os.path.join(cards_dir, f"{total + 3:02d}_全澜品牌页_微信短视频.png"), digest, platform="wechat", issue_label=issue_label)
    if logger:
        logger("🧩 正在绘制品牌页：B站版")
    _daily_digest_draw_closing(os.path.join(cards_dir, f"{total + 4:02d}_全澜品牌页_B站.png"), digest, platform="bilibili", issue_label=issue_label)
    if logger:
        logger("🧩 正在生成平台规格图：微信视频号 / B站封面与品牌页")
    _daily_digest_export_platform_ac_cards(cards_dir, digest, issue_label=issue_label, cover_background_path=cover_background_path, logger=logger)
    if logger:
        if email_after_completion:
            logger("📦 正在打包素材并发送邮件。")
        else:
            logger("📦 正在打包素材；未启用邮件发送。")
    _daily_digest_package_and_email(out_dir, enabled=bool(email_after_completion), recipient=email_recipient, logger=logger)
    if resolved_list_path and not resume_existing:
        _daily_digest_mark_list_articles_used(resolved_list_path, article_list, issue_dir=out_dir)
    if logger:
        logger(f"✅ 每日研究速递素材已生成：{out_dir}")
    return out_dir
